import React from 'react';
import { Service } from '../types';

interface ServiceCardProps {
  service: Service;
  isSelected: boolean;
  onToggle: (id: string) => void;
}

const ServiceCard: React.FC<ServiceCardProps> = ({ service, isSelected, onToggle }) => {
  // Helper to format display time
  const formatTime = (min: number, max: number, unit: 'days' | 'weeks') => {
    let minDisplay = min;
    let maxDisplay = max;
    let unitDisplay = unit === 'days' ? (max > 1 ? 'días' : 'día') : (max > 1 ? 'semanas' : 'semana');

    // Convert days to weeks for display if specifically marked in data or logic (keeping simple here based on data)
    if (unit === 'weeks') {
        minDisplay = min / 7;
        maxDisplay = max / 7;
    }

    if (minDisplay === maxDisplay) return `${minDisplay} ${unitDisplay}`;
    return `${minDisplay}–${maxDisplay} ${unitDisplay}`;
  };

  return (
    <div 
      onClick={() => onToggle(service.id)}
      className={`
        relative group cursor-pointer border rounded-sm p-5 transition-all duration-300
        ${isSelected 
          ? 'border-[#cd2027] bg-white shadow-sm' 
          : 'border-gray-100 bg-white hover:border-gray-300'
        }
      `}
    >
      <div className="flex justify-between items-start mb-2">
        <h3 className={`font-medium text-sm transition-colors ${isSelected ? 'text-black' : 'text-gray-800'}`}>
          {service.name}
        </h3>
        <div className={`
          w-4 h-4 border transition-colors flex items-center justify-center
          ${isSelected ? 'bg-[#cd2027] border-[#cd2027]' : 'border-gray-300 bg-white'}
        `}>
          {isSelected && (
            <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
            </svg>
          )}
        </div>
      </div>

      <p className="text-xs text-gray-500 mb-4 font-light leading-relaxed">
        {service.description}
      </p>

      <div className="flex items-center justify-between pt-3 border-t border-gray-50 mt-auto">
        <span className="text-xs font-semibold text-gray-900">
          {service.minPrice}–{service.maxPrice} €
        </span>
        <span className="text-xs text-gray-400 font-light">
          {formatTime(service.minDays, service.maxDays, service.unit)}
        </span>
      </div>
    </div>
  );
};

export default ServiceCard;

