import React, { useState } from 'react';
import { Totals, Category } from '../types';

interface SummaryPanelProps {
  totals: Totals;
  selectedCount: number;
  recommendation: string | null;
  onGeneratePdf: () => void;
}

const SummaryPanel: React.FC<SummaryPanelProps> = ({ 
  totals, 
  selectedCount, 
  recommendation,
  onGeneratePdf 
}) => {
  const [email, setEmail] = useState('');
  const [emailSent, setEmailSent] = useState(false);

  // Helper for time formatting
  const formatTotalTime = (minDays: number, maxDays: number) => {
    // Simple logic: if > 5 days, show weeks approximately
    const minWeeks = Math.ceil(minDays / 5); // Assuming 5 working days
    const maxWeeks = Math.ceil(maxDays / 5);

    if (minDays <= 5 && maxDays <= 5) {
       if (minDays === maxDays) return `${minDays} días`;
       return `${minDays} – ${maxDays} días`;
    }

    if (minWeeks === maxWeeks) return `${minWeeks} semanas`;
    return `${minWeeks} – ${maxWeeks} semanas`;
  };

  const handleSendEmail = (e: React.FormEvent) => {
    e.preventDefault();
    if (!email) return;

    // Simulate API call
    setEmailSent(true);
    setTimeout(() => setEmailSent(false), 3000);
  };

  const today = new Date().toLocaleDateString('es-ES', { 
    year: 'numeric', 
    month: 'long', 
    day: 'numeric' 
  });

  if (selectedCount === 0) {
    return (
      <div className="sticky top-8 bg-gray-50 p-6 rounded-sm border border-gray-100">
        <p className="text-gray-400 text-sm font-light text-center">
          Selecciona servicios para ver una estimación.
        </p>
      </div>
    );
  }

  return (
    <div className="sticky top-8 bg-white p-6 rounded-sm border border-gray-200 shadow-sm">
      <div className="flex justify-between items-center mb-6">
        <span className="text-xs uppercase tracking-widest text-gray-400">Resumen</span>
        <span className="text-xs font-mono text-gray-400">{today}</span>
      </div>

      {/* Synergies Indicator */}
      {totals.activeCategoriesCount > 1 && (
        <div className="mb-6 p-3 bg-[#cd2027]/5 border-l-2 border-[#cd2027]">
          <p className="text-[#cd2027] text-xs font-semibold mb-1">
            Sinergia Aplicada
          </p>
          <p className="text-xs text-gray-600">
            {totals.discountPercentage * 100}% de descuento por combinar {totals.activeCategoriesCount} áreas.
          </p>
        </div>
      )}

      <div className="space-y-6">
        <div>
          <p className="text-sm text-gray-500 font-light mb-1">Inversión Estimada</p>
          <div className="text-3xl font-light text-black">
            {totals.minPrice} € – {totals.maxPrice} €
          </div>
        </div>

        <div>
          <p className="text-sm text-gray-500 font-light mb-1">Tiempo Estimado</p>
          <div className="text-lg text-black">
            {formatTotalTime(totals.minDays, totals.maxDays)}
          </div>
        </div>
      </div>

      {/* Recommendation */}
      {recommendation && (
        <div className="mt-8 pt-6 border-t border-gray-100">
          <p className="text-xs font-bold text-gray-900 mb-2">Sinergia recomendada:</p>
          <p className="text-xs text-gray-500 leading-relaxed">
            {recommendation}
          </p>
        </div>
      )}

      {/* Actions */}
      <div className="mt-8 space-y-3">
        <button 
          onClick={onGeneratePdf}
          className="w-full py-3 bg-black text-white text-sm hover:bg-gray-800 transition-colors flex items-center justify-center gap-2"
        >
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
          </svg>
          Descargar PDF Resumen
        </button>

        <form onSubmit={handleSendEmail} className="flex flex-col gap-2 pt-4 border-t border-gray-100">
          <input 
            type="email" 
            placeholder="tu@email.com" 
            className="w-full text-sm p-2 border border-gray-200 focus:border-[#cd2027] focus:outline-none transition-colors"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
          />
          <button 
            type="submit"
            className="w-full py-2 text-xs font-medium text-gray-600 hover:text-[#cd2027] transition-colors"
          >
            {emailSent ? 'Copia enviada correctamente' : 'Enviar copia por email'}
          </button>
        </form>
      </div>

      <p className="text-[10px] text-gray-300 mt-6 text-center">
        Estimación orientativa. El presupuesto final se define tras reunión.
      </p>
    </div>
  );
};

export default SummaryPanel;

import { Service, Totals, Category } from '../types';

export const generatePDF = (
  selectedServices: Service[],
  activeCategories: Category[],
  totals: Totals
) => {
  if (typeof window.jspdf === 'undefined') {
    alert('Error al cargar la librería de PDF.');
    return;
  }

  const { jsPDF } = window.jspdf;
  const doc = new jsPDF();
  const pageWidth = doc.internal.pageSize.getWidth();
  const margin = 20;
  const accentColor = [205, 32, 39]; // #cd2027

  // --- Header ---
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(22);
  doc.text('La Grieta', margin, 30);

  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(100);
  doc.text('Planificador de Sinergias', margin, 36);

  // Date
  const today = new Date().toLocaleDateString('es-ES', { 
    year: 'numeric', month: 'long', day: 'numeric' 
  });
  doc.text(`Fecha: ${today}`, pageWidth - margin - 40, 30);

  doc.setDrawColor(200);
  doc.line(margin, 45, pageWidth - margin, 45);

  let yPos = 60;

  // --- Content ---
  doc.setFontSize(14);
  doc.setTextColor(0);
  doc.setFont('helvetica', 'bold');
  doc.text('Servicios Seleccionados', margin, yPos);

  yPos += 15;

  activeCategories.forEach(cat => {
    // Category Header
    doc.setFontSize(11);
    doc.setTextColor(205, 32, 39); // Accent
    doc.text(cat.title, margin, yPos);
    yPos += 8;

    // Services in this category
    const catServices = selectedServices.filter(s => cat.services.some(cs => cs.id === s.id));

    catServices.forEach(s => {
      doc.setFontSize(10);
      doc.setTextColor(0);
      doc.text(`• ${s.name}`, margin + 5, yPos);

      // Price on right
      doc.setTextColor(100);
      const priceText = `${s.minPrice} - ${s.maxPrice} €`;
      doc.text(priceText, pageWidth - margin - doc.getTextWidth(priceText), yPos);

      yPos += 7;
    });
    yPos += 5;
  });

  // --- Summary Box ---
  yPos += 10;
  doc.setFillColor(248, 248, 248);
  doc.rect(margin, yPos, pageWidth - (margin * 2), 50, 'F');

  yPos += 15;
  doc.setFontSize(12);
  doc.setTextColor(0);
  doc.setFont('helvetica', 'bold');
  doc.text('Estimación Total', margin + 10, yPos);

  if (totals.activeCategoriesCount > 1) {
    doc.setFontSize(10);
    doc.setTextColor(205, 32, 39);
    doc.text(`Sinergia aplicada: -${totals.discountPercentage * 100}%`, margin + 60, yPos);
  }

  yPos += 10;
  doc.setFontSize(16);
  doc.setTextColor(0);
  doc.text(`${totals.minPrice} € – ${totals.maxPrice} €`, margin + 10, yPos);

  yPos += 10;
  doc.setFontSize(10);
  doc.setTextColor(100);
  doc.setFont('helvetica', 'normal');
  const durationText = `Tiempo estimado: ${Math.ceil(totals.minDays/5)} - ${Math.ceil(totals.maxDays/5)} semanas (aprox)`;
  doc.text(durationText, margin + 10, yPos);

  // --- Footer ---
  doc.setFontSize(8);
  doc.setTextColor(150);
  doc.text('Nota: Estimación orientativa. El presupuesto final se define tras reunión.', margin, pageWidth - 20); // Using page height concept loosely or bottom

  doc.save('LaGrieta_Planificacion.pdf');
};

import React, { useState, useMemo } from 'react';
import Header from './components/Header';
import CategorySection from './components/CategorySection';
import SummaryPanel from './components/SummaryPanel';
import { DATA } from './constants';
import { Service, Totals } from './types';
import { generatePDF } from './utils/pdfGenerator';

const App: React.FC = () => {
  const [selectedServiceIds, setSelectedServiceIds] = useState<Set<string>>(new Set());

  const toggleService = (id: string) => {
    const newSet = new Set(selectedServiceIds);
    if (newSet.has(id)) {
      newSet.delete(id);
    } else {
      newSet.add(id);
    }
    setSelectedServiceIds(newSet);
  };

  // --- Calculations ---
  const totals = useMemo((): Totals => {
    let minPrice = 0;
    let maxPrice = 0;
    let minDays = 0;
    let maxDays = 0;

    const activeCategoriesCount = DATA.filter(cat => 
      cat.services.some(s => selectedServiceIds.has(s.id))
    ).length;

    selectedServiceIds.forEach(id => {
      // Find service in data
      let service: Service | undefined;
      for (const cat of DATA) {
        const found = cat.services.find(s => s.id === id);
        if (found) {
          service = found;
          break;
        }
      }

      if (service) {
        minPrice += service.minPrice;
        maxPrice += service.maxPrice;

        // Normalize time to days for calculation
        // Assuming 1 week = 7 days for calculation simplicity
        const mDays = service.unit === 'weeks' ? service.minDays * 7 : service.minDays;
        const xDays = service.unit === 'weeks' ? service.maxDays * 7 : service.maxDays;

        minDays += mDays;
        maxDays += xDays;
      }
    });

    // Apply Synergy Discount
    let discount = 0;
    if (activeCategoriesCount === 2) discount = 0.10;
    if (activeCategoriesCount >= 3) discount = 0.15;

    // Apply discount to total
    minPrice = Math.round(minPrice * (1 - discount));
    maxPrice = Math.round(maxPrice * (1 - discount));

    return {
      minPrice,
      maxPrice,
      minDays,
      maxDays,
      discountPercentage: discount,
      activeCategoriesCount
    };
  }, [selectedServiceIds]);

  // --- Recommendation Logic ---
  const recommendation = useMemo(() => {
    if (selectedServiceIds.size === 0) return null;

    const activeCatIds = new Set(DATA.filter(cat => 
      cat.services.some(s => selectedServiceIds.has(s.id))
    ).map(c => c.id));

    if (activeCatIds.has('branding') && activeCatIds.has('visual') && !activeCatIds.has('digital')) {
      return "Para completar la experiencia de marca, añade presencia digital y obtén un 15% de descuento.";
    }
    if (activeCatIds.has('visual') && !activeCatIds.has('branding')) {
      return "Sinergia recomendada: El contenido visual brilla más con una identidad de marca sólida.";
    }
    if (activeCatIds.has('digital') && !activeCatIds.has('visual')) {
      return "Sinergia recomendada: Una web impactante necesita contenido visual profesional.";
    }
    if (activeCatIds.has('branding') && !activeCatIds.has('digital')) {
      return "Sinergia recomendada: Lleva tu nueva identidad al mundo online.";
    }

    return null;
  }, [selectedServiceIds]);

  const handleGeneratePdf = () => {
    const selectedServicesList: Service[] = [];
    selectedServiceIds.forEach(id => {
      DATA.forEach(cat => {
        const s = cat.services.find(serv => serv.id === id);
        if (s) selectedServicesList.push(s);
      });
    });

    const activeCategories = DATA.filter(cat => 
      cat.services.some(s => selectedServiceIds.has(s.id))
    );

    generatePDF(selectedServicesList, activeCategories, totals);
  };

  return (
    <div className="min-h-screen bg-white text-black p-6 md:p-12 lg:p-20">
      <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-12">

        {/* Main Content Area */}
        <div className="lg:col-span-8">
          <Header />

          <div className="space-y-4">
            {DATA.map(category => (
              <CategorySection
                key={category.id}
                category={category}
                selectedServices={selectedServiceIds}
                onToggleService={toggleService}
                isActive={category.services.some(s => selectedServiceIds.has(s.id))}
              />
            ))}
          </div>
        </div>

        {/* Sidebar */}
        <div className="lg:col-span-4 relative">
          <SummaryPanel 
            totals={totals}
            selectedCount={selectedServiceIds.size}
            recommendation={recommendation}
            onGeneratePdf={handleGeneratePdf}
          />
        </div>

      </div>
    </div>
  );
};

export default App;

