interface CategorySectionProps {
  category: Category;
  selectedServices: Set<string>;
  onToggleService: (id: string) => void;
  isActive: boolean;
}

const SubcategoryGroup: React.FC<{
  subcategory: Subcategory;
  selectedServices: Set<string>;
  onToggleService: (id: string) => void;
}> = ({ subcategory, selectedServices, onToggleService }) => {
