import React, { useState, useMemo } from 'react';
import Header from './components/Header';
import CategorySection from './components/CategorySection';
import SummaryPanel from './components/SummaryPanel';
import { DATA } from './constants';
import { Service, Totals } from './types';
import { generatePDF } from './utils/pdfGenerator';

const App: React.FC = () => {
  const [selectedServiceIds, setSelectedServiceIds] = useState<Set<string>>(new Set());

  const toggleService = (id: string) => {
    const newSet = new Set(selectedServiceIds);
    if (newSet.has(id)) {
      newSet.delete(id);
    } else {
      newSet.add(id);
    }
    setSelectedServiceIds(newSet);
  };

  // --- Calculations ---
  const totals = useMemo((): Totals => {
    let minPrice = 0;
    let maxPrice = 0;
    let minDays = 0;
    let maxDays = 0;

    // Check which categories are active
    const activeCategoriesCount = DATA.filter(cat => 
      cat.subcategories.some(sub => 
        sub.services.some(s => selectedServiceIds.has(s.id))
      )
    ).length;

    selectedServiceIds.forEach(id => {
      // Find service in nested structure
      let service: Service | undefined;
      for (const cat of DATA) {
        for (const sub of cat.subcategories) {
          const found = sub.services.find(s => s.id === id);
          if (found) {
            service = found;
            break;
          }
        }
        if (service) break;
      }

      if (service) {
        minPrice += service.minPrice;
        maxPrice += service.maxPrice;

        // Normalize time to days for calculation (Business Days assumption: 5 days/week)
        // If the constants says 1 week, it means 1 unit of 'weeks', so multiply by 5.
        // If the constants says 3 days, it means 3 units of 'days', so multiply by 1.
        const multiplier = service.unit === 'weeks' ? 5 : 1;

        minDays += service.minDuration * multiplier;
        maxDays += service.maxDuration * multiplier;
      }
    });

    // Apply Synergy Discount
    let discount = 0;
    if (activeCategoriesCount === 2) discount = 0.10;
    if (activeCategoriesCount >= 3) discount = 0.15;

    // Apply discount to total
    minPrice = Math.round(minPrice * (1 - discount));
    maxPrice = Math.round(maxPrice * (1 - discount));

    return {
      minPrice,
      maxPrice,
      minDays,
      maxDays,
      discountPercentage: discount,
      activeCategoriesCount
    };
  }, [selectedServiceIds]);

  // --- Recommendation Logic ---
  const recommendation = useMemo(() => {
    if (selectedServiceIds.size === 0) return null;

    const activeCatIds = new Set(DATA.filter(cat => 
      cat.subcategories.some(sub => 
        sub.services.some(s => selectedServiceIds.has(s.id))
      )
    ).map(c => c.id));

    const hasBranding = activeCatIds.has('branding');
    const hasVisual = activeCatIds.has('visual');
    const hasDigital = activeCatIds.has('digital');

    if (hasBranding && hasVisual && hasDigital) {
      return "¡Proyecto integral! Esta combinación maximiza la coherencia, conversión y alcance.";
    }

    if (hasBranding && hasVisual && !hasDigital) {
      return "Sinergia recomendada: Branding + Visual + Digital = Claridad total de mensaje y alcance.";
    }

    if (hasVisual && hasDigital && !hasBranding) {
      return "Sinergia recomendada: Branding + Visual + Digital = La conversión mejora con una identidad sólida.";
    }

    if (hasBranding && hasDigital && !hasVisual) {
      return "Sinergia recomendada: Branding + Visual + Digital = El contenido visual conecta tu identidad con la audiencia.";
    }

    if (hasBranding && !hasVisual && !hasDigital) {
      return "Sugerencia: Añade Visual Content para mejorar la coherencia visual de la marca.";
    }

    if (hasVisual && !hasBranding && !hasDigital) {
      return "Sugerencia: Un buen Branding potencia el impacto de tu contenido visual.";
    }

    if (hasDigital && !hasBranding && !hasVisual) {
      return "Sugerencia: El contenido Visual y Branding aumentan la conversión web.";
    }

    return null;
  }, [selectedServiceIds]);

  const handleGeneratePdf = () => {
    // Flatten services list for PDF generation helper
    const selectedServicesList: Service[] = [];
    selectedServiceIds.forEach(id => {
      DATA.forEach(cat => {
        cat.subcategories.forEach(sub => {
          const s = sub.services.find(serv => serv.id === id);
          if (s) selectedServicesList.push(s);
        });
      });
    });

    // Pass full structure to handle subcategories in PDF
    const activeCategories = DATA.filter(cat => 
      cat.subcategories.some(sub => 
        sub.services.some(s => selectedServiceIds.has(s.id))
      )
    );

    generatePDF(selectedServicesList, activeCategories, totals);
  };

  return (
    <div className="min-h-screen bg-white text-black p-6 md:p-12 lg:p-20">
      <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-12">

        {/* Main Content Area */}
        <div className="lg:col-span-8">
          <Header />

          <div className="space-y-4">
            {DATA.map(category => (
              <CategorySection
                key={category.id}
                category={category}
                selectedServices={selectedServiceIds}
                onToggleService={toggleService}
                isActive={category.subcategories.some(sub => 
                  sub.services.some(s => selectedServiceIds.has(s.id))
                )}
              />
            ))}
          </div>
        </div>

        {/* Sidebar */}
        <div className="lg:col-span-4 relative">
          <SummaryPanel 
            totals={totals}
            selectedCount={selectedServiceIds.size}
            recommendation={recommendation}
            onGeneratePdf={handleGeneratePdf}
          />
        </div>

      </div>
    </div>
  );
};

export default App;

import { Service, Totals, Category } from '../types';

export const generatePDF = (
  selectedServices: Service[],
  activeCategories: Category[],
  totals: Totals
) => {
  if (typeof window.jspdf === 'undefined') {
    alert('Error al cargar la librería de PDF.');
    return;
  }

  const { jsPDF } = window.jspdf;
  const doc = new jsPDF();
  const pageWidth = doc.internal.pageSize.getWidth();
  const margin = 20;

  // --- Header ---
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(22);
  doc.text('La Grieta', margin, 30);

  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(100);
  doc.text('Planificador de Sinergias', margin, 36);

  // Date
  const today = new Date().toLocaleDateString('es-ES', { 
    year: 'numeric', month: 'long', day: 'numeric' 
  });
  doc.text(`Fecha: ${today}`, pageWidth - margin - 40, 30);

  doc.setDrawColor(200);
  doc.line(margin, 45, pageWidth - margin, 45);

  let yPos = 60;

  // --- Content ---
  doc.setFontSize(14);
  doc.setTextColor(0);
  doc.setFont('helvetica', 'bold');
  doc.text('Servicios Seleccionados', margin, yPos);

  yPos += 15;

  activeCategories.forEach(cat => {
    // Category Header
    doc.setFontSize(12);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(205, 32, 39); // Accent
    doc.text(cat.title, margin, yPos);
    yPos += 8;

    // Filter subcategories that have selected services
    const activeSubcats = cat.subcategories.filter(sub => 
        sub.services.some(s => selectedServices.some(sel => sel.id === s.id))
    );

    activeSubcats.forEach(sub => {
        // Subcategory Header
        doc.setFontSize(10);
        doc.setFont('helvetica', 'bold');
        doc.setTextColor(50);
        doc.text(sub.title, margin + 5, yPos);
        yPos += 6;

        // Services
        const subServices = sub.services.filter(s => selectedServices.some(sel => sel.id === s.id));

        subServices.forEach(s => {
            doc.setFontSize(10);
            doc.setFont('helvetica', 'normal');
            doc.setTextColor(0);
            doc.text(`• ${s.name}`, margin + 10, yPos);

            // Price on right
            doc.setTextColor(100);
            const priceText = `${s.minPrice} - ${s.maxPrice} €`;
            doc.text(priceText, pageWidth - margin - doc.getTextWidth(priceText), yPos);

            yPos += 6;
        });
        yPos += 4;
    });

    yPos += 5;

    // Page break check (simple approximation)
    if (yPos > 250) {
        doc.addPage();
        yPos = 30;
    }
  });

  // --- Summary Box ---
  yPos += 10;
  // Page break check before summary
  if (yPos > 220) {
      doc.addPage();
      yPos = 30;
  }

  doc.setFillColor(248, 248, 248);
  doc.rect(margin, yPos, pageWidth - (margin * 2), 50, 'F');

  yPos += 15;
  doc.setFontSize(12);
  doc.setTextColor(0);
  doc.setFont('helvetica', 'bold');
  doc.text('Estimación Total', margin + 10, yPos);

  if (totals.activeCategoriesCount > 1) {
    doc.setFontSize(10);
    doc.setTextColor(205, 32, 39);
    doc.text(`Sinergia aplicada: -${totals.discountPercentage * 100}%`, margin + 60, yPos);
  }

  yPos += 10;
  doc.setFontSize(16);
  doc.setTextColor(0);
  doc.text(`${totals.minPrice} € – ${totals.maxPrice} €`, margin + 10, yPos);

  yPos += 10;
  doc.setFontSize(10);
  doc.setTextColor(100);
  doc.setFont('helvetica', 'normal');
  const durationText = `Tiempo estimado: ${Math.ceil(totals.minDays/5)} - ${Math.ceil(totals.maxDays/5)} semanas (aprox)`;
  doc.text(durationText, margin + 10, yPos);

  // --- Footer ---
  doc.setFontSize(8);
  doc.setTextColor(150);
  doc.text('Nota: Estimación orientativa. El presupuesto final se define tras reunión.', margin, 280);

  doc.save('LaGrieta_Planificacion.pdf');
};

