import React, { useState, useEffect } from 'react';
import { Category, Subcategory } from '../types';
import ServiceCard from './ServiceCard';

interface CategorySectionProps {
  category: Category;
  selectedServices: Set<string>;
  onToggleService: (id: string) => void;
  isActive: boolean;
}

const CategorySection: React.FC<CategorySectionProps> = ({ 
  category, 
  selectedServices, 
  onToggleService,
  isActive
}) => {
  // State to track active subcategory tab. Default to first one.
  const [activeSubTab, setActiveSubTab] = useState<string>(category.subcategories[0]?.id || '');

  // If a user selects a service in a different tab (logic elsewhere) or we want to highlight active tabs
  // We can add effects here. For now, simple tab switching.

  const activeSubcategory = category.subcategories.find(sub => sub.id === activeSubTab);

  return (
    <div className={`mb-16 transition-opacity duration-500 ${isActive ? 'opacity-100' : 'opacity-80 hover:opacity-100'}`}>
      <div className="flex items-baseline gap-3 mb-6">
        <h2 className={`text-2xl font-light ${isActive ? 'text-black' : 'text-gray-500'}`}>
          {category.title}
        </h2>
        {isActive && <span className="text-[10px] uppercase tracking-wider text-[#cd2027] font-bold">Activo</span>}
      </div>

      {/* Horizontal Tabs Navigation */}
      <div className="flex overflow-x-auto gap-2 mb-6 pb-2 border-b border-gray-100 no-scrollbar">
        {category.subcategories.map(sub => {
            const isTabActive = activeSubTab === sub.id;
            const hasSelection = sub.services.some(s => selectedServices.has(s.id));

            return (
                <button
                    key={sub.id}
                    onClick={() => setActiveSubTab(sub.id)}
                    className={`
                        whitespace-nowrap px-4 py-2 text-sm font-medium rounded-sm transition-all relative
                        ${isTabActive 
                            ? 'bg-gray-100 text-black' 
                            : 'text-gray-500 hover:text-black hover:bg-gray-50'
                        }
                    `}
                >
                    {sub.title}
                    {/* Dot indicator for selected items in other tabs */}
                    {hasSelection && (
                        <span className={`absolute top-1 right-1 w-1.5 h-1.5 rounded-full ${isTabActive ? 'bg-[#cd2027]' : 'bg-gray-300'}`} />
                    )}
                </button>
            )
        })}
      </div>

      {/* Content Area */}
      <div className="min-h-[200px]">
        {activeSubcategory && (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 animate-fadeIn">
                {activeSubcategory.services.map(service => (
                <ServiceCard
                    key={service.id}
                    service={service}
