import React from 'react';
import { ServiceStats } from '../types';

interface StatsRadarProps {
  stats: ServiceStats;
}

const StatsRadar: React.FC<StatsRadarProps> = ({ stats }) => {
  // Normalize stats to 0-100 range for the chart (assuming max somewhat around 30-40 for a full project)
  // We'll map them relative to a "Max Potential" to make it look cool.
  const MAX_VAL = 30; 

  const norm = (val: number) => Math.min((val / MAX_VAL) * 100, 100);

  const b = norm(stats.brand);
  const c = norm(stats.conversion);
  const r = norm(stats.reach);

  // SVG Coordinates
  // Triangle pointing up. 
  // Center: 100, 100
  // Top (Brand): 100, 20
  // Bottom Right (Conversion): 170, 140
  // Bottom Left (Reach): 30, 140

  const center = { x: 100, y: 100 };
  const radius = 80;

  // Calculate points on the axis based on values
  // Axis 1: Top (Brand) - Angle -90deg (270)
  const brandY = center.y - (radius * (b / 100));
  const brandX = center.x;

  // Axis 2: Bottom Right (Conversion) - Angle 30deg
  const rad30 = 30 * (Math.PI / 180);
  const convX = center.x + (radius * (c / 100)) * Math.cos(rad30);
  const convY = center.y + (radius * (c / 100)) * Math.sin(rad30);

  // Axis 3: Bottom Left (Reach) - Angle 150deg
  const rad150 = 150 * (Math.PI / 180);
  const reachX = center.x + (radius * (r / 100)) * Math.cos(rad150);
  const reachY = center.y + (radius * (r / 100)) * Math.sin(rad150);

  const points = `${brandX},${brandY} ${convX},${convY} ${reachX},${reachY}`;

  return (
    <div className="w-full flex flex-col items-center justify-center py-4 bg-gray-50 rounded-sm mb-6 border border-gray-100 relative overflow-hidden">
        <p className="text-[10px] uppercase tracking-widest text-gray-400 absolute top-2 left-3">Impacto del Proyecto</p>

        <svg width="200" height="180" viewBox="0 0 200 180">
            {/* Background Triangle */}
            <polygon points="100,20 169,140 31,140" fill="none" stroke="#e5e7eb" strokeWidth="1" />
            <polygon points="100,60 135,120 65,120" fill="none" stroke="#f3f4f6" strokeWidth="1" />

            {/* Axis Lines */}
            <line x1="100" y1="100" x2="100" y2="20" stroke="#e5e7eb" strokeDasharray="4 2" />
            <line x1="100" y1="100" x2="169" y2="140" stroke="#e5e7eb" strokeDasharray="4 2" />
            <line x1="100" y1="100" x2="31" y2="140" stroke="#e5e7eb" strokeDasharray="4 2" />

            {/* Data Shape */}
            <polygon points={points} fill="rgba(205, 32, 39, 0.15)" stroke="#cd2027" strokeWidth="2" />

            {/* Points */}
            <circle cx={brandX} cy={brandY} r="3" fill="#cd2027" />
            <circle cx={convX} cy={convY} r="3" fill="#cd2027" />
            <circle cx={reachX} cy={reachY} r="3" fill="#cd2027" />

            {/* Labels */}
            <text x="100" y="15" textAnchor="middle" fontSize="10" fill="#6b7280" className="uppercase font-bold">Brand</text>
            <text x="175" y="150" textAnchor="middle" fontSize="10" fill="#6b7280" className="uppercase font-bold">Sales</text>
            <text x="25" y="150" textAnchor="middle" fontSize="10" fill="#6b7280" className="uppercase font-bold">Reach</text>
        </svg>

        <div className="flex justify-between w-full px-8 mt-2 text-[10px] text-gray-400 font-mono">
           <span>LVL: {Math.floor((stats.brand + stats.conversion + stats.reach) / 5)}</span>
           <span>PWR: {stats.brand + stats.conversion + stats.reach}</span>
        </div>
    </div>
  );
};

