import React, { useState, useMemo } from 'react';
import Header from './components/Header';
import CategorySection from './components/CategorySection';
import SummaryPanel from './components/SummaryPanel';
import { DATA } from './constants';
import { Service, Totals, ServiceStats } from './types';
import { generatePDF } from './utils/pdfGenerator';

const App: React.FC = () => {
  const [selectedServiceIds, setSelectedServiceIds] = useState<Set<string>>(new Set());

  const toggleService = (id: string) => {
    const newSet = new Set(selectedServiceIds);
    if (newSet.has(id)) {
      newSet.delete(id);
    } else {
      newSet.add(id);
    }
    setSelectedServiceIds(newSet);
  };

  // Helper to get selected service objects
  const getSelectedServicesList = () => {
    const list: Service[] = [];
    selectedServiceIds.forEach(id => {
      for (const cat of DATA) {
        for (const sub of cat.subcategories) {
          const s = sub.services.find(serv => serv.id === id);
          if (s) {
            list.push(s);
            break;
          }
        }
      }
    });
    return list;
  };

  const selectedServicesList = getSelectedServicesList();

  // --- Calculations ---
  const totals = useMemo((): Totals => {
    let minPrice = 0;
    let maxPrice = 0;
    let minDays = 0;
    let maxDays = 0;

    // Stats accumulators
    let totalStats: ServiceStats = { brand: 0, conversion: 0, reach: 0 };

    // Check which categories are active
    const activeCategoriesCount = DATA.filter(cat => 
      cat.subcategories.some(sub => 
        sub.services.some(s => selectedServiceIds.has(s.id))
      )
    ).length;

    selectedServicesList.forEach(service => {
        minPrice += service.minPrice;
        maxPrice += service.maxPrice;

        const multiplier = service.unit === 'weeks' ? 5 : 1;

        minDays += service.minDuration * multiplier;
        maxDays += service.maxDuration * multiplier;

        // Sum stats
        totalStats.brand += service.stats.brand;
        totalStats.conversion += service.stats.conversion;
        totalStats.reach += service.stats.reach;
    });

    // Apply Synergy Discount
    let discount = 0;
    if (activeCategoriesCount === 2) discount = 0.10;
    if (activeCategoriesCount >= 3) discount = 0.15;

    // Apply discount to total
    minPrice = Math.round(minPrice * (1 - discount));
    maxPrice = Math.round(maxPrice * (1 - discount));

    return {
      minPrice,
      maxPrice,
      minDays,
      maxDays,
      discountPercentage: discount,
      activeCategoriesCount,
      totalStats
    };
  }, [selectedServiceIds, selectedServicesList]);

  // --- Recommendation Logic ---
  const recommendation = useMemo(() => {
    if (selectedServiceIds.size === 0) return null;

    const activeCatIds = new Set(DATA.filter(cat => 
      cat.subcategories.some(sub => 
        sub.services.some(s => selectedServiceIds.has(s.id))
      )
    ).map(c => c.id));

    const hasBranding = activeCatIds.has('branding');
    const hasVisual = activeCatIds.has('visual');
    const hasDigital = activeCatIds.has('digital');

    if (hasBranding && hasVisual && hasDigital) {
      return "¡Sinergia Máxima! Tu proyecto cubre los 3 pilares fundamentales.";
    }

    if (hasBranding && hasVisual && !hasDigital) {
      return "Tip: Añade presencia digital para capitalizar tu imagen de marca.";
    }

    if (hasVisual && hasDigital && !hasBranding) {
      return "Tip: Una web bonita no vende sin una identidad de marca sólida (Branding).";
    }

    if (hasBranding && hasDigital && !hasVisual) {
      return "Tip: Humaniza tu marca digital con contenido visual auténtico.";
    }

    if (hasBranding && !hasVisual && !hasDigital) {
      return "Oportunidad: El Branding es solo el inicio. ¿Cómo lo mostrarás al mundo?";
    }

    if (hasVisual && !hasBranding && !hasDigital) {
      return "Cuidado: El contenido visual sin estrategia de marca suele perder impacto.";
    }

    if (hasDigital && !hasBranding && !hasVisual) {
      return "Alerta: Una web sin contenido ni marca es solo código vacío.";
    }

    return null;
  }, [selectedServiceIds]);

  const handleGeneratePdf = () => {
    const activeCategories = DATA.filter(cat => 
      cat.subcategories.some(sub => 
        sub.services.some(s => selectedServiceIds.has(s.id))
      )
    );
    generatePDF(selectedServicesList, activeCategories, totals);
  };

  return (
    <div className="min-h-screen bg-white text-black p-6 md:p-12 lg:p-20">
      <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-12">

        {/* Main Content Area */}
        <div className="lg:col-span-8">
          <Header />

          <div className="space-y-4">
            {DATA.map(category => (
              <CategorySection
                key={category.id}
                category={category}
                selectedServices={selectedServiceIds}
                onToggleService={toggleService}
                isActive={category.subcategories.some(sub => 
                  sub.services.some(s => selectedServiceIds.has(s.id))
                )}
              />
            ))}
          </div>
        </div>

        {/* Sidebar */}
        <div className="lg:col-span-4 relative">
          <SummaryPanel 
            totals={totals}
            selectedCount={selectedServiceIds.size}
            recommendation={recommendation}
            selectedServicesList={selectedServicesList}
            onGeneratePdf={handleGeneratePdf}
          />
        </div>

      </div>
    </div>
  );
};

export default App;

export interface ServiceStats {
  brand: number;
  conversion: number;
  reach: number;
}

export interface Tier {
  id: 'essential' | 'pro' | 'premium';
  name: string; // e.g., "Básico", "Completo", "Excelencia"
  price: number;
  duration: number;
  unit: 'days' | 'weeks';
  description: string; // Specific detail: "Up to 5 photos" vs "Up to 20 photos"
}

export interface Service {
  id: string;
  name: string;
  description: string; // General description
  tiers: Tier[];       // The 3 specific options
  stats: ServiceStats;
}

export interface Subcategory {
  id: string;
  title: string;
  services: Service[];
}

export interface Category {
  id: string;
  title: string;
  description: string;
  subcategories: Subcategory[];
}

export interface SelectedService {
  serviceId: string;
  tierId: 'essential' | 'pro' | 'premium';
  price: number;
  duration: number; // normalized to days for calculation
  stats: ServiceStats;
}

export interface Totals {
  minPrice: number; // Now represents actual total
  maxPrice: number; // Kept for interface compatibility, but effectively same as minPrice in fixed calc
  minDays: number;
  maxDays: number;
  discountPercentage: number;
  activeCategoriesCount: number;
  totalStats: ServiceStats;
}

