  onToggle: (id: string, tierId?: 'essential' | 'pro' | 'premium') => void;
}

const ServiceCard: React.FC<ServiceCardProps> = ({ service, selectedTierId, onToggle }) => {
  const isSelected = !!selectedTierId;

  // Find min and max for the "From..." display when not selected
  const minPrice = Math.min(...service.tiers.map(t => t.price));
  const maxPrice = Math.max(...service.tiers.map(t => t.price));

  const handleCardClick = () => {
    if (!isSelected) {
      // Default to 'pro' (middle tier) when first clicked
      onToggle(service.id, 'pro');
    } else {
        // If already selected, clicking the header/outside toggles it off
        onToggle(service.id);
    }
  };

  const handleTierClick = (e: React.MouseEvent, tierId: 'essential' | 'pro' | 'premium') => {
    e.stopPropagation(); // Prevent card toggle
    onToggle(service.id, tierId);
  };

  return (
    <div 
