import React, { useState, useMemo } from 'react';
import Header from './components/Header';
import CategorySection from './components/CategorySection';
import SummaryPanel from './components/SummaryPanel';
import { DATA } from './constants';
import { Service, Totals, ServiceStats, SelectedService } from './types';
import { generatePDF } from './utils/pdfGenerator';

// Extended type for UI display
interface SelectedServiceUI extends SelectedService {
  name: string;
}

const App: React.FC = () => {
  // Store selected services as Map: ServiceID -> TierID
  const [selectedServicesMap, setSelectedServicesMap] = useState<Map<string, string>>(new Map());

  const toggleService = (id: string, tierId?: 'essential' | 'pro' | 'premium') => {
    const newMap = new Map(selectedServicesMap);
    if (!tierId) {
      // Toggle off if no tier provided (header click when active)
      if (newMap.has(id)) {
        newMap.delete(id);
      }
    } else {
      // Set specific tier
      newMap.set(id, tierId);
    }
    setSelectedServicesMap(newMap);
  };

  // Helper to extract full data objects
  const selectedServicesList = useMemo((): SelectedServiceUI[] => {
    const list: SelectedServiceUI[] = [];

    selectedServicesMap.forEach((tierId, serviceId) => {
        // Find the service data
        for (const cat of DATA) {
            for (const sub of cat.subcategories) {
                const s = sub.services.find(serv => serv.id === serviceId);
                if (s) {
                    const tier = s.tiers.find(t => t.id === tierId);
                    if (tier) {
                        const multiplier = tier.unit === 'weeks' ? 5 : 1;
                        list.push({
                            serviceId: s.id,
                            name: s.name,
                            tierId: tierId as 'essential' | 'pro' | 'premium',
                            price: tier.price,
                            duration: tier.duration * multiplier,
                            stats: s.stats
                        });
                    }
                    return; // Break inner loop if found
                }
            }
        }
    });
    return list;
  }, [selectedServicesMap]);

  // --- Calculations ---
  const totals = useMemo((): Totals => {
    let totalPrice = 0;
    let totalDays = 0;
    let totalStats: ServiceStats = { brand: 0, conversion: 0, reach: 0 };

    // Check which categories are active
    const activeCategoriesCount = DATA.filter(cat => 
      cat.subcategories.some(sub => 
        sub.services.some(s => selectedServicesMap.has(s.id))
      )
    ).length;

    selectedServicesList.forEach(item => {
        totalPrice += item.price;
        totalDays += item.duration; // Already normalized in list generation

        // We can optionally scale stats by tier here
        // E.g., Premium gets 100% stats, Basic gets 60%. 
        // For simplicity, let's keep base stats but maybe add +1 for pro, +2 for premium?
        let statMultiplier = 1;
        if (item.tierId === 'pro') statMultiplier = 1.2;
        if (item.tierId === 'premium') statMultiplier = 1.5;

        totalStats.brand += item.stats.brand * statMultiplier;
        totalStats.conversion += item.stats.conversion * statMultiplier;
        totalStats.reach += item.stats.reach * statMultiplier;
    });

    // Apply Synergy Discount
    let discount = 0;
    if (activeCategoriesCount === 2) discount = 0.10;
    if (activeCategoriesCount >= 3) discount = 0.15;

    // Apply discount to total
    const finalPrice = Math.round(totalPrice * (1 - discount));

    return {
      minPrice: finalPrice, // Exact calculation now
      maxPrice: finalPrice,
      minDays: totalDays,
      maxDays: totalDays,
      discountPercentage: discount,
      activeCategoriesCount,
      totalStats
    };
  }, [selectedServicesMap, selectedServicesList]);

  // --- Recommendation Logic ---
  const recommendation = useMemo(() => {
    if (selectedServicesMap.size === 0) return null;

    const activeCatIds = new Set(DATA.filter(cat => 
      cat.subcategories.some(sub => 
        sub.services.some(s => selectedServicesMap.has(s.id))
      )
    ).map(c => c.id));

    const hasBranding = activeCatIds.has('branding');
    const hasVisual = activeCatIds.has('visual');
    const hasDigital = activeCatIds.has('digital');

    if (hasBranding && hasVisual && hasDigital) {
      return "¡Sinergia Máxima! Proyecto integral activo.";
    }

    if (hasBranding && hasVisual && !hasDigital) {
      return "Tip: Añade presencia digital para capitalizar tu imagen de marca.";
    }

    if (hasVisual && hasDigital && !hasBranding) {
      return "Tip: Una web bonita no vende sin una identidad de marca sólida (Branding).";
    }

    if (hasBranding && hasDigital && !hasVisual) {
      return "Tip: Humaniza tu marca digital con contenido visual auténtico.";
    }

    if (hasBranding && !hasVisual && !hasDigital) {
      return "Oportunidad: El Branding es solo el inicio. ¿Cómo lo mostrarás al mundo?";
    }

    if (hasVisual && !hasBranding && !hasDigital) {
      return "Cuidado: El contenido visual sin estrategia de marca suele perder impacto.";
    }

    if (hasDigital && !hasBranding && !hasVisual) {
      return "Alerta: Una web sin contenido ni marca es solo código vacío.";
    }

    return null;
  }, [selectedServicesMap]);

  const handleGeneratePdf = () => {
    // Need to pass the tier selection to the generator
    const activeCategories = DATA.filter(cat => 
      cat.subcategories.some(sub => 
        sub.services.some(s => selectedServicesMap.has(s.id))
      )
    );
    // Passing the map to lookup selected tiers
    generatePDF(selectedServicesList, activeCategories, totals);
  };

  return (
    <div className="min-h-screen bg-white text-black p-6 md:p-12 lg:p-20">
      <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-12">

        {/* Main Content Area */}
        <div className="lg:col-span-8">
          <Header />

          <div className="space-y-4">
            {DATA.map(category => (
              <CategorySection
                key={category.id}
                category={category}
                selectedServices={selectedServicesMap}
                onToggleService={toggleService}
                isActive={category.subcategories.some(sub => 
                  sub.services.some(s => selectedServicesMap.has(s.id))
                )}
              />
            ))}
          </div>
        </div>

        {/* Sidebar */}
        <div className="lg:col-span-4 relative">
          <SummaryPanel 
            totals={totals}
            selectedCount={selectedServicesMap.size}
            recommendation={recommendation}
            selectedServicesList={selectedServicesList}
            onGeneratePdf={handleGeneratePdf}
          />
        </div>

      </div>
    </div>
  );
};

export default App;

import { Category, Totals, SelectedService } from '../types';

interface SelectedServiceUI extends SelectedService {
  name: string;
}

export const generatePDF = (
  selectedServices: SelectedServiceUI[],
  activeCategories: Category[],
  totals: Totals
) => {
  if (typeof window.jspdf === 'undefined') {
    alert('Error al cargar la librería de PDF.');
    return;
  }

  const { jsPDF } = window.jspdf;
  const doc = new jsPDF();
  const pageWidth = doc.internal.pageSize.getWidth();
  const margin = 20;

  // --- Header ---
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(22);
  doc.text('La Grieta', margin, 30);

  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(100);
  doc.text('Planificador de Sinergias', margin, 36);

  // Date
  const today = new Date().toLocaleDateString('es-ES', { 
    year: 'numeric', month: 'long', day: 'numeric' 
  });
  doc.text(`Fecha: ${today}`, pageWidth - margin - 40, 30);

  doc.setDrawColor(200);
  doc.line(margin, 45, pageWidth - margin, 45);

  let yPos = 60;

  // --- Content ---
  doc.setFontSize(14);
  doc.setTextColor(0);
  doc.setFont('helvetica', 'bold');
  doc.text('Servicios Seleccionados', margin, yPos);

  yPos += 15;

  activeCategories.forEach(cat => {
    // Only print category if it has selected services
    const categoryHasSelection = selectedServices.some(sel => {
        // We have to reverse lookup if this service ID belongs to this category.
        // Or simpler: check against the passed activeCategories which are already filtered in App.tsx
        return cat.subcategories.some(sub => sub.services.some(s => s.id === sel.serviceId));
    });

    if (!categoryHasSelection) return;

    // Category Header
    doc.setFontSize(12);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(205, 32, 39); // Accent
    doc.text(cat.title, margin, yPos);
    yPos += 8;

    // Subcategories
    cat.subcategories.forEach(sub => {
         const subServices = selectedServices.filter(sel => 
             sub.services.some(s => s.id === sel.serviceId)
         );

         if (subServices.length === 0) return;

         doc.setFontSize(10);
         doc.setFont('helvetica', 'bold');
         doc.setTextColor(50);
         doc.text(sub.title, margin + 5, yPos);
         yPos += 6;

         subServices.forEach(s => {
            doc.setFontSize(10);
            doc.setFont('helvetica', 'normal');
            doc.setTextColor(0);

            // Format: • Service Name (TIER NAME)
            const tierName = s.tierId.toUpperCase();
            doc.text(`• ${s.name}`, margin + 10, yPos);

            doc.setFontSize(8);
            doc.setTextColor(120);
            doc.text(`[${tierName}]`, margin + 10 + doc.getTextWidth(`• ${s.name}`) + 2, yPos);

            // Price on right
            doc.setFontSize(10);
            doc.setTextColor(50);
            const priceText = `${s.price} €`;
            doc.text(priceText, pageWidth - margin - doc.getTextWidth(priceText), yPos);

            yPos += 6;
         });
         yPos += 4;
    });

    yPos += 5;

    // Page break check
    if (yPos > 250) {
        doc.addPage();
        yPos = 30;
    }
  });

  // --- Summary Box ---
  yPos += 10;
  if (yPos > 220) {
      doc.addPage();
      yPos = 30;
  }

  doc.setFillColor(248, 248, 248);
  doc.rect(margin, yPos, pageWidth - (margin * 2), 50, 'F');

  yPos += 15;
  doc.setFontSize(12);
  doc.setTextColor(0);
  doc.setFont('helvetica', 'bold');
  doc.text('Estimación Total', margin + 10, yPos);

  if (totals.activeCategoriesCount > 1) {
    doc.setFontSize(10);
    doc.setTextColor(205, 32, 39);
    doc.text(`Sinergia aplicada: -${totals.discountPercentage * 100}%`, margin + 60, yPos);
  }

  yPos += 10;
  doc.setFontSize(16);
  doc.setTextColor(0);
  doc.text(`${totals.minPrice} €`, margin + 10, yPos);

  yPos += 10;
  doc.setFontSize(10);
  doc.setTextColor(100);
  doc.setFont('helvetica', 'normal');

  const weeks = Math.ceil(totals.minDays / 5);
  const durationText = `Tiempo estimado: ${totals.minDays <= 5 ? totals.minDays + ' días' : weeks + ' semanas'} (aprox)`;
  doc.text(durationText, margin + 10, yPos);

  // --- Footer ---
  doc.setFontSize(8);
  doc.setTextColor(150);
  doc.text('Nota: Estimación orientativa basada en módulos estándar. El presupuesto final se define tras reunión.', margin, 280);

  doc.save('LaGrieta_Planificacion.pdf');
};

export interface ServiceStats {
  brand: number;
  conversion: number;
  reach: number;
}

export interface Tier {
  id: 'essential' | 'pro' | 'premium';
  name: string; // e.g., "Básico", "Completo", "Excelencia"
  price: number;
  duration: number;
  unit: 'days' | 'weeks' | 'hours';
  description: string; // Specific detail: "Up to 5 photos" vs "Up to 20 photos"
}

export interface Service {
  id: string;
  name: string;
  description: string; // General description
  tiers: Tier[];       // The 3 specific options
  stats: ServiceStats;
}

export interface Subcategory {
  id: string;
  title: string;
  services: Service[];
}

export interface Category {
  id: string;
  title: string;
  description: string;
  subcategories: Subcategory[];
}

export interface SelectedService {
  serviceId: string;
  tierId: 'essential' | 'pro' | 'premium';
  price: number;
  duration: number; // normalized to days for calculation
  stats: ServiceStats;
}

export interface Totals {
  minPrice: number; // Now represents actual total
  maxPrice: number; // Kept for interface compatibility, but effectively same as minPrice in fixed calc
  minDays: number;
  maxDays: number;
  discountPercentage: number;
  activeCategoriesCount: number;
  totalStats: ServiceStats;
}

// Global declaration for jsPDF loaded via CDN
declare global {
  interface Window {
    jspdf: {
      jsPDF: new (options?: any) => any;
    };
  }
}

import React from 'react';
import { Service, Tier } from '../types';

interface ServiceCardProps {
  service: Service;
  selectedTierId: string | undefined; // If undefined, not selected
  onToggle: (id: string, tierId?: 'essential' | 'pro' | 'premium') => void;
}

const ServiceCard: React.FC<ServiceCardProps> = ({ service, selectedTierId, onToggle }) => {
  const isSelected = !!selectedTierId;

  // Find min and max for the "From..." display when not selected
  const minPrice = Math.min(...service.tiers.map(t => t.price));
  const maxPrice = Math.max(...service.tiers.map(t => t.price));

  const handleCardClick = () => {
    if (!isSelected) {
      // Default to 'pro' (middle tier) when first clicked
      onToggle(service.id, 'pro');
    } else {
        // If already selected, clicking the header/outside toggles it off
        onToggle(service.id);
    }
  };

  const handleTierClick = (e: React.MouseEvent, tierId: 'essential' | 'pro' | 'premium') => {
    e.stopPropagation(); // Prevent card toggle
    onToggle(service.id, tierId);
  };

  const getDurationLabel = (duration: number, unit: 'days' | 'weeks' | 'hours') => {
      if (unit === 'weeks') return duration > 1 ? 'semanas' : 'semana';
      if (unit === 'days') return duration > 1 ? 'días' : 'día';
      if (unit === 'hours') return duration > 1 ? 'horas' : 'hora';
      return '';
  }

  return (
    <div 
      className={`
        relative border rounded-sm p-5 transition-all duration-300 flex flex-col group
        ${isSelected 
          ? 'border-[#cd2027] bg-white shadow-md ring-1 ring-[#cd2027]/10' 
          : 'border-gray-100 bg-white hover:border-gray-300'
        }
      `}
    >
      {/* Header Section - Clickable to toggle whole card */}
      <div className="cursor-pointer" onClick={handleCardClick}>
          <div className="flex justify-between items-start mb-2">
            <h3 className={`font-medium text-sm transition-colors pr-2 ${isSelected ? 'text-black' : 'text-gray-800'}`}>
              {service.name}
            </h3>
            <div className={`
              w-4 h-4 border transition-colors flex items-center justify-center flex-shrink-0
              ${isSelected ? 'bg-[#cd2027] border-[#cd2027]' : 'border-gray-300 bg-white'}
            `}>
              {isSelected && (
                <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                </svg>
              )}
            </div>
          </div>

          <p className="text-xs text-gray-500 mb-4 font-light leading-relaxed">
            {service.description}
          </p>
      </div>

      {/* Tier Selector - Only visible when selected */}
      {isSelected ? (
          <div className="mt-auto pt-3 border-t border-gray-100 animate-fadeIn">
            <p className="text-[10px] uppercase text-gray-400 font-bold mb-2 tracking-wider">Nivel de Servicio</p>
            <div className="grid grid-cols-3 gap-1 mb-3">
                {service.tiers.map((tier) => (
                    <button
                        key={tier.id}
                        onClick={(e) => handleTierClick(e, tier.id)}
                        className={`
                            px-1 py-1.5 text-[10px] rounded-sm border transition-all text-center
                            ${selectedTierId === tier.id 
                                ? 'bg-black text-white border-black font-medium' 
                                : 'bg-gray-50 text-gray-500 border-transparent hover:bg-gray-100'
                            }
                        `}
                    >
                        {tier.name}
                    </button>
                ))}
            </div>
            {/* Active Tier Details */}
            {service.tiers.map(tier => (
                 selectedTierId === tier.id && (
                    <div key={tier.id} className="text-xs">
                        <p className="text-gray-600 mb-1 font-medium">{tier.description}</p>
                        <div className="flex justify-between text-[#cd2027] font-semibold mt-2">
                            <span>{tier.price} €</span>
                            <span>{tier.duration} {getDurationLabel(tier.duration, tier.unit)}</span>
                        </div>
                    </div>
                 )
            ))}
          </div>
      ) : (
        /* Default Footer - Range */
        <div className="flex items-center justify-between pt-3 border-t border-gray-50 mt-auto">
            <span className="text-xs font-semibold text-gray-900">
            Desde {minPrice} €
            </span>
            <span className="text-[10px] text-gray-400 uppercase tracking-wide">
                Configurable
            </span>
        </div>
      )}

      <style>{`
        @keyframes fadeIn {
            from { opacity: 0; transform: translateY(-5px); }
            to { opacity: 1; transform: translateY(0); }
        }
        .animate-fadeIn {
            animation: fadeIn 0.2s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

