      // Toggle off if no tier provided (header click when active)
      if (newMap.has(id)) {
        newMap.delete(id);
      }
    } else {
      // Set specific tier
      newMap.set(id, tierId);
    }
    setSelectedServicesMap(newMap);
  };

  // Helper to extract full data objects
  const selectedServicesList = useMemo((): SelectedServiceUI[] => {
    const list: SelectedServiceUI[] = [];

    selectedServicesMap.forEach((tierId, serviceId) => {
        // Find the service data
        for (const cat of DATA) {
            for (const sub of cat.subcategories) {
                const s = sub.services.find(serv => serv.id === serviceId);
                if (s) {
                    const tier = s.tiers.find(t => t.id === tierId);
                    if (tier) {
                        let multiplier = 1;
                        if (tier.unit === 'weeks') multiplier = 5;
                        else if (tier.unit === 'hours') multiplier = 1/8; // 8 hours work day approximation

                        list.push({
                            serviceId: s.id,
                            name: s.name,
                            tierId: tierId as 'essential' | 'pro' | 'premium',
                            price: tier.price,
                            duration: tier.duration * multiplier,
                            stats: s.stats
                        });
                    }
                    return; // Break inner loop if found
                }
            }
        }
    });
    return list;
  }, [selectedServicesMap]);

  // --- Calculations ---
  const totals = useMemo((): Totals => {
    let totalPrice = 0;
    let totalDays = 0;
    let totalStats: ServiceStats = { brand: 0, conversion: 0, reach: 0 };

    // Check which categories are active
    const activeCategoriesCount = DATA.filter(cat => 
      cat.subcategories.some(sub => 
        sub.services.some(s => selectedServicesMap.has(s.id))
      )
    ).length;

    selectedServicesList.forEach(item => {
        totalPrice += item.price;
        totalDays += item.duration; // Already normalized in list generation

        // We can optionally scale stats by tier here
        // E.g., Premium gets 100% stats, Basic gets 60%. 
        // For simplicity, let's keep base stats but maybe add +1 for pro, +2 for premium?
        let statMultiplier = 1;
        if (item.tierId === 'pro') statMultiplier = 1.2;
        if (item.tierId === 'premium') statMultiplier = 1.5;

        totalStats.brand += item.stats.brand * statMultiplier;
        totalStats.conversion += item.stats.conversion * statMultiplier;
        totalStats.reach += item.stats.reach * statMultiplier;
    });

    // Apply Synergy Discount
    let discount = 0;
    if (activeCategoriesCount === 2) discount = 0.10;
    if (activeCategoriesCount >= 3) discount = 0.15;

    // Apply discount to total
    const finalPrice = Math.round(totalPrice * (1 - discount));

    return {
      minPrice: finalPrice, // Exact calculation now
      maxPrice: finalPrice,
      minDays: totalDays,
      maxDays: totalDays,
      discountPercentage: discount,
      activeCategoriesCount,
      totalStats
    };
  }, [selectedServicesMap, selectedServicesList]);

  // --- Recommendation Logic ---
  const recommendation = useMemo(() => {
    if (selectedServicesMap.size === 0) return null;

    const activeCatIds = new Set(DATA.filter(cat => 
      cat.subcategories.some(sub => 
        sub.services.some(s => selectedServicesMap.has(s.id))
      )
    ).map(c => c.id));

    const hasBranding = activeCatIds.has('branding');
    const hasVisual = activeCatIds.has('visual');
    const hasDigital = activeCatIds.has('digital');

    if (hasBranding && hasVisual && hasDigital) {
      return "¡Sinergia Máxima! Proyecto integral activo.";
    }

    if (hasBranding && hasVisual && !hasDigital) {
      return "Tip: Añade presencia digital para capitalizar tu imagen de marca.";
    }

    if (hasVisual && hasDigital && !hasBranding) {
      return "Tip: Una web bonita no vende sin una identidad de marca sólida (Branding).";
    }

    if (hasBranding && hasDigital && !hasVisual) {
      return "Tip: Humaniza tu marca digital con contenido visual auténtico.";
    }

    if (hasBranding && !hasVisual && !hasDigital) {
      return "Oportunidad: El Branding es solo el inicio. ¿Cómo lo mostrarás al mundo?";
    }

    if (hasVisual && !hasBranding && !hasDigital) {
      return "Cuidado: El contenido visual sin estrategia de marca suele perder impacto.";
    }

    if (hasDigital && !hasBranding && !hasVisual) {
      return "Alerta: Una web sin contenido ni marca es solo código vacío.";
    }

    return null;
  }, [selectedServicesMap]);

  const handleGeneratePdf = () => {
    // Need to pass the tier selection to the generator
    const activeCategories = DATA.filter(cat => 
      cat.subcategories.some(sub => 
        sub.services.some(s => selectedServicesMap.has(s.id))
      )
    );
    // Passing the map to lookup selected tiers
    generatePDF(selectedServicesList, activeCategories, totals);
  };

  return (
    <div className="min-h-screen bg-white text-black p-6 md:p-12 lg:p-20">
      <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-12">

        {/* Main Content Area */}
        <div className="lg:col-span-8">
          <Header />

          <div className="space-y-4">
            {DATA.map(category => (
              <CategorySection
                key={category.id}
                category={category}
                selectedServices={selectedServicesMap}
                onToggleService={toggleService}
                isActive={category.subcategories.some(sub => 
                  sub.services.some(s => selectedServicesMap.has(s.id))
                )}
              />
            ))}
          </div>
        </div>

        {/* Sidebar */}
        <div className="lg:col-span-4 relative">
          <SummaryPanel 
            totals={totals}
            selectedCount={selectedServicesMap.size}
            recommendation={recommendation}
            selectedServicesList={selectedServicesList}
            onGeneratePdf={handleGeneratePdf}
          />
        </div>

      </div>
    </div>
  );
};

