import React from 'react';
import { ServiceStats } from '../types';

interface StatsRadarProps {
  stats: ServiceStats;
  potentialStats?: ServiceStats; // New: For "Ghost" projection
}

const StatsRadar: React.FC<StatsRadarProps> = ({ stats, potentialStats }) => {
  const MAX_VAL = 40; 

  const norm = (val: number) => Math.min((val / MAX_VAL) * 100, 100);

  // Helper to generate points string
  const getPoints = (s: ServiceStats) => {
    const b = norm(s.brand);
    const c = norm(s.conversion);
    const r = norm(s.reach);

    const center = { x: 100, y: 100 };
    const radius = 80;

    const brandY = center.y - (radius * (b / 100));
    const brandX = center.x;

    const rad30 = 30 * (Math.PI / 180);
    const convX = center.x + (radius * (c / 100)) * Math.cos(rad30);
    const convY = center.y + (radius * (c / 100)) * Math.sin(rad30);

    const rad150 = 150 * (Math.PI / 180);
    const reachX = center.x + (radius * (r / 100)) * Math.cos(rad150);
    const reachY = center.y + (radius * (r / 100)) * Math.sin(rad150);

    return `${brandX},${brandY} ${convX},${convY} ${reachX},${reachY}`;
  };

  const points = getPoints(stats);
  const ghostPoints = potentialStats ? getPoints(potentialStats) : '';

  return (
    <div className="w-full flex flex-col items-center justify-center py-4 bg-white relative overflow-hidden">
        {/* Title removed, context handled by parent */}

        <svg width="220" height="190" viewBox="0 0 200 180" className="overflow-visible">
            {/* Background Grid */}
            <polygon points="100,20 169,140 31,140" fill="none" stroke="#f3f4f6" strokeWidth="1" />
            <polygon points="100,60 135,120 65,120" fill="none" stroke="#f3f4f6" strokeWidth="1" />

            {/* Axis Lines */}
            <line x1="100" y1="100" x2="100" y2="20" stroke="#f3f4f6" strokeDasharray="4 2" />
            <line x1="100" y1="100" x2="169" y2="140" stroke="#f3f4f6" strokeDasharray="4 2" />
            <line x1="100" y1="100" x2="31" y2="140" stroke="#f3f4f6" strokeDasharray="4 2" />

            {/* Ghost Shape (Potential) */}
            {potentialStats && (
               <polygon 
                  points={ghostPoints} 
                  fill="none" 
                  stroke="#fbbf24" 
                  strokeWidth="2" 
                  strokeDasharray="4 4"
                  className="animate-pulse"
               >
                 <title>Proyección con servicio recomendado</title>
               </polygon>
            )}

            {/* Actual Data Shape */}
            <polygon points={points} fill="rgba(205, 32, 39, 0.1)" stroke="#cd2027" strokeWidth="2">
              <title>Impacto actual del proyecto</title>
            </polygon>

            {/* Labels with Tooltips */}
            <g className="cursor-help">
               <text x="100" y="10" textAnchor="middle" fontSize="10" fill="#6b7280" className="uppercase font-bold tracking-wider">Brand</text>
               <title>Impacto en percepción de marca y autoridad</title>
            </g>
            <g className="cursor-help">
               <text x="185" y="150" textAnchor="middle" fontSize="10" fill="#6b7280" className="uppercase font-bold tracking-wider">Sales</text>
               <title>Potencial de conversión y ventas directas</title>
            </g>
            <g className="cursor-help">
               <text x="15" y="150" textAnchor="middle" fontSize="10" fill="#6b7280" className="uppercase font-bold tracking-wider">Reach</text>
               <title>Alcance de audiencia y visibilidad</title>
            </g>
        </svg>

        <div className="flex justify-between w-full px-6 mt-2 text-[10px] text-gray-400 font-mono">
           <div className="text-center">
             <span className="block text-xl text-gray-800 font-light">{Math.floor((stats.brand + stats.conversion + stats.reach) / 3)}</span>
             <span className="uppercase">Score</span>
           </div>
           {potentialStats && (
             <div className="text-center text-amber-500">
               <span className="block text-xl font-bold">+{Math.floor(((potentialStats.brand + potentialStats.conversion + potentialStats.reach) - (stats.brand + stats.conversion + stats.reach)))}</span>
               <span className="uppercase">Boost</span>
             </div>
           )}
        </div>
    </div>
  );
};

