interface CategorySectionProps {
  category: Category;
  selectedServices: Map<string, string>; // ID -> TierID
  relatedServices: Set<string>; // IDs of related services to highlight
  onToggleService: (id: string, tierId?: 'essential' | 'pro' | 'premium') => void;
  isActive: boolean;
}

const CategorySection: React.FC<CategorySectionProps> = ({ 
  category, 
  selectedServices, 
  relatedServices,
  onToggleService,
  isActive
}) => {
  const [activeSubTab, setActiveSubTab] = useState<string>(category.subcategories[0]?.id || '');

  const activeSubcategory = category.subcategories.find(sub => sub.id === activeSubTab);

  return (
    <div className={`mb-16 transition-opacity duration-500 ${isActive ? 'opacity-100' : 'opacity-80 hover:opacity-100'}`}>
      <div className="flex items-baseline gap-3 mb-6">
        <h2 className={`text-2xl font-light ${isActive ? 'text-black' : 'text-gray-500'}`}>
          {category.title}
        </h2>
        {isActive && <span className="text-[10px] uppercase tracking-wider text-[#cd2027] font-bold">Activo</span>}
      </div>

      {/* Horizontal Tabs Navigation */}
      <div className="flex overflow-x-auto gap-2 mb-6 pb-2 border-b border-gray-100 no-scrollbar">
        {category.subcategories.map(sub => {
            const isTabActive = activeSubTab === sub.id;
            const hasSelection = sub.services.some(s => selectedServices.has(s.id));

            return (
                <button
                    key={sub.id}
                    onClick={() => setActiveSubTab(sub.id)}
                    className={`
                        whitespace-nowrap px-6 py-2 text-sm font-medium transition-all relative border border-gray-200
                        ${isTabActive 
                            ? 'bg-black text-white border-black' 
                            : 'text-gray-500 bg-white hover:border-gray-400 hover:text-black'
                        }
                    `}
                >
                    {sub.title}
                    {hasSelection && (
                        <span className={`absolute -top-1 -right-1 w-2 h-2 ${isTabActive ? 'bg-[#cd2027]' : 'bg-[#cd2027]'}`} />
                    )}
                </button>
            )
        })}
      </div>

      {/* Content Area */}
      <div className="min-h-[200px]">
        {activeSubcategory && (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-fadeIn">
                {activeSubcategory.services.map(service => (
                <ServiceCard
                    key={service.id}
                    service={service}
                    selectedTierId={selectedServices.get(service.id)}
                    isRelated={relatedServices.has(service.id)}
                    onToggle={onToggleService}
                />
                ))}
