import React, { useState } from 'react';
import { Totals, SelectedService, ServiceStats } from '../types';
import StatsRadar from './StatsRadar';

interface Recommendation {
  text: string;
  serviceId?: string;
  serviceName?: string;
  potentialStats?: ServiceStats;
}

interface SummaryPanelProps {
  totals: Totals;
  selectedCount: number;
  recommendation: Recommendation | null;
  selectedServicesList: SelectedService[]; 
  onGeneratePdf: () => void;
  onAddRecommendation: (id: string) => void;
}

const SummaryPanel: React.FC<SummaryPanelProps> = ({ 
  totals, 
  selectedCount, 
  recommendation,
  selectedServicesList,
  onGeneratePdf,
  onAddRecommendation
}) => {
  const [email, setEmail] = useState('');
  const [emailSent, setEmailSent] = useState(false);

  const formatTotalTime = (totalDays: number) => {
    if (totalDays <= 5) return `${totalDays} DÍAS`;
    const weeks = Math.ceil(totalDays / 5);
    return `${weeks} SEMANAS`;
  };

  const handleSendEmail = (e: React.FormEvent) => {
    e.preventDefault();
    if (!email) return;
    setEmailSent(true);
    setTimeout(() => setEmailSent(false), 3000);
  };

  const CircularChart = ({ value, label, color }: { value: number, label: string, color: string }) => {
    const radius = 18;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (Math.min(value, 100) / 100) * circumference;

    return (
        <div className="flex flex-col items-center gap-1 group cursor-help w-full border border-gray-200 py-3 hover:border-black transition-colors bg-white">
            <div className="relative w-12 h-12 flex items-center justify-center">
                <svg className="w-full h-full transform -rotate-90">
                    <circle cx="24" cy="24" r={radius} stroke="#e5e7eb" strokeWidth="2" fill="none" />
                    <circle 
                        cx="24" cy="24" r={radius} 
                        stroke={color} strokeWidth="2" fill="none" 
                        strokeDasharray={circumference} 
                        strokeDashoffset={offset}
                        className="transition-all duration-1000 ease-out"
                    />
                </svg>
                <span className="absolute text-[10px] font-bold text-black font-mono">{value}%</span>
            </div>
            <span className="text-[9px] uppercase tracking-widest text-gray-500 font-bold group-hover:text-black transition-colors">{label}</span>
        </div>
    )
  }

  const ResourceCounter = ({ icon, count, label }: { icon: string, count: number, label: string }) => (
      <div className="flex flex-col items-center justify-center p-2 border border-gray-200 bg-white hover:border-black transition-colors h-20">
          <span className="text-lg mb-1">{icon}</span>
          <span className="text-lg font-bold text-black font-mono leading-none">{count}</span>
          <span className="text-[9px] uppercase text-gray-400 tracking-wider mt-1">{label}</span>
      </div>
  );

  if (selectedCount === 0) {
    return (
      <div className="sticky top-8 bg-gray-50 border-2 border-dashed border-gray-300 p-8 text-center">
        <div className="w-12 h-12 border-2 border-gray-300 mx-auto mb-4 flex items-center justify-center text-gray-400">
             <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
        </div>
        <h3 className="font-bold uppercase tracking-widest text-gray-900 mb-2 text-sm">Proyecto Vacío</h3>
        <p className="text-gray-500 text-xs font-mono">
          Inicie secuencia de selección para calcular recursos.
        </p>
      </div>
    );
  }

  // Normalize stats
  const MAX_STAT = 40;
  const brandPct = Math.round((totals.totalStats.brand / MAX_STAT) * 100);
  const convPct = Math.round((totals.totalStats.conversion / MAX_STAT) * 100);
  const reachPct = Math.round((totals.totalStats.reach / MAX_STAT) * 100);

  return (
    <div className="sticky top-8 bg-gray-50 border-2 border-black max-h-[90vh] overflow-y-auto custom-scrollbar flex flex-col">

      {/* Header & Price */}
      <div className="p-6 border-b-2 border-black bg-white">
          <div className="flex justify-between items-center mb-4">
            <span className="text-[10px] uppercase tracking-[0.2em] text-black font-bold">Resumen de Inversión</span>
            <div className={`px-2 py-1 text-[9px] font-bold uppercase tracking-widest border ${totals.activeCategoriesCount > 1 ? 'border-[#cd2027] text-[#cd2027] bg-[#cd2027]/5' : 'border-gray-300 text-gray-400'}`}>
                {totals.activeCategoriesCount > 1 ? `Sinergia Lvl.${totals.activeCategoriesCount}` : 'Estándar'}
            </div>
          </div>

          <div className="flex items-baseline gap-3">
             {totals.finalPrice < totals.originalPrice && (
                 <span className="text-sm font-mono text-gray-400 line-through decoration-red-500 decoration-1">
                     {totals.originalPrice}€
                 </span>
             )}
             <span className="text-4xl font-bold tracking-tighter text-black font-mono">
                 {totals.finalPrice}<span className="text-xl">€</span>
             </span>
          </div>
          <div className="mt-4 flex items-center gap-2 border-t border-gray-100 pt-2">
              <span className="text-[9px] uppercase font-bold text-gray-400 tracking-wider">ETA:</span>
              <span className="text-xs font-mono font-bold text-black">{formatTotalTime(totals.maxDays)}</span>
          </div>
      </div>

      {/* Metrics Section */}
      <div className="p-6 bg-gray-50">
          {/* Radar Chart Container */}
          <div className="bg-white border border-gray-200 mb-4 shadow-sm p-2">
             <StatsRadar 
                stats={totals.totalStats} 
                potentialStats={recommendation?.potentialStats}
             />
          </div>

          {/* Circular Stats Grid */}
          <div className="grid grid-cols-3 gap-[-1px] mb-4">
             <CircularChart value={brandPct} label="Brand" color="#000" />
             <CircularChart value={convPct} label="Sales" color="#000" />
             <CircularChart value={reachPct} label="Reach" color="#000" />
          </div>

          {/* Resources Counters Grid */}
          <div className="grid grid-cols-3 gap-2">
              <ResourceCounter icon="📷" count={totals.totalResources.photos} label="Fotos" />
              <ResourceCounter icon="🎥" count={totals.totalResources.videos} label="Videos" />
              <ResourceCounter icon="✍️" count={totals.totalResources.posts} label="Posts" />
          </div>
      </div>

      {/* Recommendation Engine */}
      {recommendation && (
        <div className="bg-amber-50 border-y-2 border-amber-200 p-5">
            <div className="flex flex-col gap-2">
                <div className="flex items-center gap-2 mb-1">
                     <span className="w-2 h-2 bg-amber-500"></span>
                     <p className="text-[10px] font-bold text-amber-900 uppercase tracking-widest">Oportunidad Táctica</p>
                </div>

                <p className="text-xs text-amber-900 font-mono leading-relaxed mb-3 pl-4 border-l-2 border-amber-200">
                    {recommendation.text}
                </p>

                {recommendation.serviceId && (
                    <button 
                        onClick={() => onAddRecommendation(recommendation.serviceId!)}
                        className="flex items-center justify-between text-[10px] bg-white border border-amber-900 px-4 py-3 font-bold uppercase tracking-wider text-amber-900 hover:bg-amber-900 hover:text-white transition-colors w-full"
                    >
                        <span>[ + ] Añadir {recommendation.serviceName}</span>
                        <span className="opacity-70 font-mono">+KPIs</span>
                    </button>
                )}
            </div>
        </div>
      )}

      {/* Action Footer */}
      <div className="p-6 bg-white border-t-2 border-black space-y-3 mt-auto">
        <button 
          onClick={onGeneratePdf}
          className="w-full py-4 bg-black text-white text-xs uppercase tracking-[0.2em] font-bold hover:bg-[#cd2027] transition-colors flex items-center justify-center gap-3 border border-black"
        >
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
          </svg>
          Exportar Informe
        </button>

        <form onSubmit={handleSendEmail} className="relative group">
          <input 
            type="email" 
            placeholder="EMAIL DESTINATARIO..." 
            className="w-full text-xs font-mono p-3 pl-4 bg-white border border-gray-300 focus:border-black focus:ring-0 outline-none transition-colors uppercase placeholder:text-gray-300"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
          />
          <button 
            type="submit"
            className="absolute right-1 top-1 bottom-1 px-4 bg-gray-100 hover:bg-black hover:text-white text-[9px] font-bold transition-colors uppercase tracking-wider border-l border-gray-200"
          >
            {emailSent ? 'ENVIADO' : 'ENVIAR'}
          </button>
        </form>
      </div>
    </div>
  );
};

