import { Category, Totals, SelectedService } from '../types';

interface SelectedServiceUI extends SelectedService {
  name: string;
}

export const generatePDF = (
  selectedServices: SelectedServiceUI[],
  activeCategories: Category[],
  totals: Totals
) => {
  if (typeof window.jspdf === 'undefined') {
    alert('Error al cargar la librería de PDF.');
    return;
  }

  const { jsPDF } = window.jspdf;
  const doc = new jsPDF();
  const pageWidth = doc.internal.pageSize.getWidth();
  const margin = 20;

  // --- Header ---
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(22);
  doc.text('La Grieta', margin, 30);

  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(100);
  doc.text('Planificador de Sinergias', margin, 36);

  // Date
  const today = new Date().toLocaleDateString('es-ES', { 
    year: 'numeric', month: 'long', day: 'numeric' 
  });
  doc.text(`Fecha: ${today}`, pageWidth - margin - 40, 30);

  doc.setDrawColor(0);
  doc.setLineWidth(0.5);
  doc.line(margin, 45, pageWidth - margin, 45);

  let yPos = 60;

  // --- Content ---
  doc.setFontSize(14);
  doc.setTextColor(0);
  doc.setFont('helvetica', 'bold');
  doc.text('Servicios Seleccionados', margin, yPos);

  yPos += 15;

  activeCategories.forEach(cat => {
    // Only print category if it has selected services
    const categoryHasSelection = selectedServices.some(sel => {
        return cat.subcategories.some(sub => sub.services.some(s => s.id === sel.serviceId));
    });

    if (!categoryHasSelection) return;

    // Category Header
    doc.setFontSize(12);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(205, 32, 39); // Accent
    doc.text(cat.title.toUpperCase(), margin, yPos);
    yPos += 8;

    // Subcategories
    cat.subcategories.forEach(sub => {
         const subServices = selectedServices.filter(sel => 
             sub.services.some(s => s.id === sel.serviceId)
         );

         if (subServices.length === 0) return;

         doc.setFontSize(10);
         doc.setFont('helvetica', 'bold');
         doc.setTextColor(50);
         doc.text(sub.title, margin + 5, yPos);
         yPos += 6;

         subServices.forEach(s => {
            doc.setFontSize(10);
            doc.setFont('helvetica', 'normal');
            doc.setTextColor(0);

            // Format: • Service Name (TIER NAME)
            const tierName = s.tierId.toUpperCase();
            doc.text(`• ${s.name}`, margin + 10, yPos);

            doc.setFontSize(8);
            doc.setTextColor(120);
            doc.text(`[${tierName}]`, margin + 10 + doc.getTextWidth(`• ${s.name}`) + 2, yPos);

            // Price on right
            doc.setFontSize(10);
            doc.setTextColor(50);
            const priceText = `${s.price} €`;
            doc.text(priceText, pageWidth - margin - doc.getTextWidth(priceText), yPos);

            yPos += 6;
         });
         yPos += 4;
    });

    yPos += 5;

    // Page break check
    if (yPos > 250) {
        doc.addPage();
        yPos = 30;
    }
  });

  // --- Summary Box ---
  yPos += 10;
  if (yPos > 200) {
      doc.addPage();
      yPos = 30;
  }

  // Draw Box
  doc.setDrawColor(0);
  doc.setLineWidth(0.5);
  doc.rect(margin, yPos, pageWidth - (margin * 2), 70); // Taller box

  let boxY = yPos + 10;

  doc.setFontSize(10);
  doc.setTextColor(0);
  doc.setFont('helvetica', 'bold');
  doc.text('DESGLOSE DE INVERSIÓN', margin + 10, boxY);

  // Subtotal
  boxY += 10;
  doc.setFont('helvetica', 'normal');
  doc.text('Subtotal:', margin + 10, boxY);
  doc.text(`${totals.originalPrice} €`, pageWidth - margin - 30, boxY, { align: 'right' });

  // Synergy Discount
  if (totals.synergyLevel > 0) {
    boxY += 6;
    doc.setTextColor(205, 32, 39);
    doc.text(`Descuento Sinergia (${totals.synergyLevel === 2 ? '15%' : '10%'}):`, margin + 10, boxY);
    doc.text(`-${totals.synergyDiscountAmount} €`, pageWidth - margin - 30, boxY, { align: 'right' });
  }

  // Portfolio Discount
  if (totals.isPortfolioActive) {
      boxY += 6;
      doc.setTextColor(205, 32, 39);
      doc.text(`Descuento Protocolo P0RT4F0L10 (20%):`, margin + 10, boxY);
      doc.text(`-${totals.portfolioDiscountAmount} €`, pageWidth - margin - 30, boxY, { align: 'right' });
  }

  // Line
  boxY += 8;
  doc.setDrawColor(200);
  doc.line(margin + 10, boxY, pageWidth - margin - 10, boxY);

  // Final Total
  boxY += 10;
  doc.setFontSize(16);
  doc.setTextColor(0);
  doc.setFont('helvetica', 'bold');
  doc.text('TOTAL ESTIMADO:', margin + 10, boxY);
  doc.text(`${totals.finalPrice} €`, pageWidth - margin - 30, boxY, { align: 'right' });

  // Time
  boxY += 8;
  doc.setFontSize(10);
  doc.setTextColor(100);
  doc.setFont('helvetica', 'normal');
  const weeks = Math.ceil(totals.minDays / 5);
  const durationText = `Tiempo operativo estimado: ${totals.minDays <= 5 ? totals.minDays + ' días' : weeks + ' semanas'}`;
  doc.text(durationText, margin + 10, boxY);

  // --- Legal / Protocol Footer ---
  yPos += 80;
  doc.setFontSize(8);
  doc.setTextColor(150);

  const footerText = [
      'Nota: Estimación orientativa basada en módulos estándar. El presupuesto final se define tras reunión.',
      totals.isPortfolioActive ? 'CLÁUSULA PROTOCOLO P0RT4F0L10: El cliente autoriza a La Grieta a publicar el trabajo resultante en su portafolio web y redes sociales con fines promocionales, a cambio del descuento aplicado del 20%.' : ''
  ];

  doc.text(footerText, margin, yPos);

  doc.save('LaGrieta_Planificacion.pdf');
};

import React, { useState, useMemo } from 'react';
import Header from './components/Header';
import CategorySection from './components/CategorySection';
import SummaryPanel from './components/SummaryPanel';
import { DATA } from './constants';
import { Service, Totals, ServiceStats, SelectedService, Resources } from './types';
import { generatePDF } from './utils/pdfGenerator';

interface SelectedServiceUI extends SelectedService {
  name: string;
}

// Interface for the smart recommendation object
interface Recommendation {
  text: string;
  serviceId?: string;
  serviceName?: string;
  potentialStats?: ServiceStats;
}

const App: React.FC = () => {
  const [selectedServicesMap, setSelectedServicesMap] = useState<Map<string, string>>(new Map());
  const [lastSelectedServiceId, setLastSelectedServiceId] = useState<string | null>(null);
  const [isPortfolioActive, setIsPortfolioActive] = useState(false);

  const toggleService = (id: string, tierId?: 'essential' | 'pro' | 'premium') => {
    const newMap = new Map(selectedServicesMap);
    if (!tierId) {
      if (newMap.has(id)) {
        newMap.delete(id);
      }
    } else {
      newMap.set(id, tierId);
      setLastSelectedServiceId(id);
    }
    setSelectedServicesMap(newMap);
  };

  const selectedServicesList = useMemo((): SelectedServiceUI[] => {
    const list: SelectedServiceUI[] = [];
    selectedServicesMap.forEach((tierId, serviceId) => {
        for (const cat of DATA) {
            for (const sub of cat.subcategories) {
                const s = sub.services.find(serv => serv.id === serviceId);
                if (s) {
                    const tier = s.tiers.find(t => t.id === tierId);
                    if (tier) {
                        let multiplier = 1;
                        if (tier.unit === 'weeks') multiplier = 5;
                        else if (tier.unit === 'hours') multiplier = 1/8; 

                        list.push({
                            serviceId: s.id,
                            name: s.name,
                            tierId: tierId as 'essential' | 'pro' | 'premium',
                            price: tier.price,
                            duration: tier.duration * multiplier,
                            stats: s.stats,
                            resources: tier.resources
                        });
                    }
                    return;
                }
            }
        }
    });
    return list;
  }, [selectedServicesMap]);

  // --- Calculations ---
  const totals = useMemo((): Totals => {
    let totalPrice = 0;
    let totalDays = 0;
    let totalStats: ServiceStats = { brand: 0, conversion: 0, reach: 0 };
    let totalResources: Resources = { photos: 0, videos: 0, posts: 0, hours: 0 };

    // Logic Changed: Count services, not categories
    const servicesCount = selectedServicesList.length;

    selectedServicesList.forEach(item => {
        totalPrice += item.price;
        totalDays += item.duration;

        let statMultiplier = 1;
        if (item.tierId === 'pro') statMultiplier = 1.2;
        if (item.tierId === 'premium') statMultiplier = 1.5;

        totalStats.brand += item.stats.brand * statMultiplier;
        totalStats.conversion += item.stats.conversion * statMultiplier;
        totalStats.reach += item.stats.reach * statMultiplier;

        // Sum Resources
        totalResources.photos += item.resources.photos;
        totalResources.videos += item.resources.videos;
        totalResources.posts += item.resources.posts;
        totalResources.hours += item.resources.hours;
    });

    // 1. Synergy Discount Logic
    let synergyDiscountPercent = 0;
    if (servicesCount === 2) synergyDiscountPercent = 0.10;
    if (servicesCount >= 3) synergyDiscountPercent = 0.15;

    const synergyDiscountAmount = Math.round(totalPrice * synergyDiscountPercent);
    const priceAfterSynergy = totalPrice - synergyDiscountAmount;

    // 2. Portfolio Protocol Logic
    let portfolioDiscountAmount = 0;
    if (isPortfolioActive) {
        portfolioDiscountAmount = Math.round(priceAfterSynergy * 0.20);
    }

    const finalPrice = priceAfterSynergy - portfolioDiscountAmount;

    return {
      originalPrice: totalPrice,
      synergyDiscountAmount,
      portfolioDiscountAmount,
      finalPrice: finalPrice,
      minDays: totalDays,
      maxDays: totalDays,
      synergyLevel: servicesCount >= 3 ? 2 : (servicesCount === 2 ? 1 : 0),
      isPortfolioActive,
      totalStats,
      totalResources
    };
  }, [selectedServicesMap, selectedServicesList, isPortfolioActive]);

  // --- Smart Recommendation Engine ---
  const recommendation = useMemo((): Recommendation | null => {
    if (selectedServicesMap.size === 0) return null;

    // 1. Context Aware: Check last selected service relations
    if (lastSelectedServiceId) {
        // Find the service object
        let lastService: Service | undefined;
        for (const cat of DATA) {
            for (const sub of cat.subcategories) {
                const s = sub.services.find(serv => serv.id === lastSelectedServiceId);
                if (s) { lastService = s; break; }
            }
        }

        if (lastService && lastService.relatedServiceIds) {
            // Find a related service that is NOT selected
            const recommendationId = lastService.relatedServiceIds.find(rid => !selectedServicesMap.has(rid));

            if (recommendationId) {
                // Find details of the recommended service
                let recService: Service | undefined;
                for (const cat of DATA) {
                     for (const sub of cat.subcategories) {
                        const s = sub.services.find(serv => serv.id === recommendationId);
                        if (s) { recService = s; break; }
                     }
                }

                if (recService) {
                    // Calculate Potential Stats (Assuming 'pro' tier for the ghost preview)
                    const projectedStats = { ...totals.totalStats };
                    projectedStats.brand += recService.stats.brand * 1.2;
                    projectedStats.conversion += recService.stats.conversion * 1.2;
                    projectedStats.reach += recService.stats.reach * 1.2;

                    return {
                        text: `Basado en "${lastService.name}", añade "${recService.name}" para potenciar resultados.`,
                        serviceId: recService.id,
                        serviceName: recService.name,
                        potentialStats: projectedStats
                    };
                }
            }
        }
    }

    // 2. Fallback: Category Gaps (General Logic)
    const activeCatIds = new Set(DATA.filter(cat => 
      cat.subcategories.some(sub => 
        sub.services.some(s => selectedServicesMap.has(s.id))
      )
    ).map(c => c.id));

    if (activeCatIds.has('branding') && !activeCatIds.has('digital')) {
       return { text: "Tip: Tienes marca. Añade Web/Redes para capitalizarla." };
    }
    if (activeCatIds.has('digital') && !activeCatIds.has('visual')) {
       return { text: "Tip: El contenido es el rey. Añade foto/video." };
    }

    return null;
  }, [selectedServicesMap, lastSelectedServiceId, totals.totalStats]);

  // --- Related Services Set for UI Highlights ---
  const relatedServicesSet = useMemo(() => {
     const set = new Set<string>();
     if (lastSelectedServiceId) {
        let lastService: Service | undefined;
        for (const cat of DATA) {
            for (const sub of cat.subcategories) {
                const s = sub.services.find(serv => serv.id === lastSelectedServiceId);
                if (s) { lastService = s; break; }
            }
        }
        if (lastService) {
            lastService.relatedServiceIds.forEach(id => set.add(id));
        }
     }
     return set;
  }, [lastSelectedServiceId]);

  const handleGeneratePdf = () => {
    const activeCategories = DATA.filter(cat => 
      cat.subcategories.some(sub => 
        sub.services.some(s => selectedServicesMap.has(s.id))
      )
    );
    generatePDF(selectedServicesList, activeCategories, totals);
  };

  const handleAddRecommendation = (id: string) => {
      toggleService(id, 'pro'); // Default to Pro
  }

  return (
    <div className="min-h-screen bg-white text-black p-6 md:p-12 lg:p-20 font-inter">
      <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-12">

        {/* Main Content Area */}
        <div className="lg:col-span-8">
          <Header />

          <div className="space-y-4">
            {DATA.map(category => (
              <CategorySection
                key={category.id}
                category={category}
                selectedServices={selectedServicesMap}
                relatedServices={relatedServicesSet}
                onToggleService={toggleService}
                isActive={category.subcategories.some(sub => 
                  sub.services.some(s => selectedServicesMap.has(s.id))
                )}
              />
            ))}
          </div>
        </div>

        {/* Sidebar */}
        <div className="lg:col-span-4 relative">
          <SummaryPanel 
            totals={totals}
            selectedCount={selectedServicesMap.size}
            recommendation={recommendation}
            selectedServicesList={selectedServicesList}
            onGeneratePdf={handleGeneratePdf}
            onAddRecommendation={handleAddRecommendation}
            onTogglePortfolio={() => setIsPortfolioActive(!isPortfolioActive)}
          />
        </div>

      </div>
    </div>
  );
};

export default App;

export interface ServiceStats {
  brand: number;
  conversion: number;
  reach: number;
}

export interface Resources {
  photos: number;
  videos: number;
  posts: number;
