import React from 'react';
import { ServiceStats } from '../types';

interface StatsRadarProps {
  stats: ServiceStats;
  potentialStats?: ServiceStats; // New: For "Ghost" projection
}

const StatsRadar: React.FC<StatsRadarProps> = ({ stats, potentialStats }) => {
  const MAX_VAL = 40; 

  const norm = (val: number) => Math.min((val / MAX_VAL) * 100, 100);

  // Helper to generate points string
  const getPoints = (s: ServiceStats) => {
    const b = norm(s.brand);
    const c = norm(s.conversion);
    const r = norm(s.reach);

    const center = { x: 80, y: 70 }; // Adjusted center for smaller viewbox
    const radius = 50;

    const brandY = center.y - (radius * (b / 100));
    const brandX = center.x;

    const rad30 = 30 * (Math.PI / 180);
    const convX = center.x + (radius * (c / 100)) * Math.cos(rad30);
    const convY = center.y + (radius * (c / 100)) * Math.sin(rad30);

    const rad150 = 150 * (Math.PI / 180);
    const reachX = center.x + (radius * (r / 100)) * Math.cos(rad150);
    const reachY = center.y + (radius * (r / 100)) * Math.sin(rad150);

    return `${brandX},${brandY} ${convX},${convY} ${reachX},${reachY}`;
  };

  const points = getPoints(stats);
  const ghostPoints = potentialStats ? getPoints(potentialStats) : '';

  return (
    <div className="w-full h-full flex items-center justify-center relative overflow-hidden">
        <svg width="100%" height="100%" viewBox="0 0 160 140" className="overflow-visible" preserveAspectRatio="xMidYMid meet">
            {/* Background Grid - Triangle */}
            <polygon points="80,20 123.3,95 36.7,95" fill="none" stroke="#f3f4f6" strokeWidth="1" />
            <polygon points="80,45 101.6,82.5 58.4,82.5" fill="none" stroke="#f3f4f6" strokeWidth="1" />

            {/* Axis Lines */}
            <line x1="80" y1="70" x2="80" y2="20" stroke="#f3f4f6" strokeDasharray="2 2" />
            <line x1="80" y1="70" x2="123.3" y2="95" stroke="#f3f4f6" strokeDasharray="2 2" />
            <line x1="80" y1="70" x2="36.7" y2="95" stroke="#f3f4f6" strokeDasharray="2 2" />

            {/* Ghost Shape (Potential) */}
            {potentialStats && (
               <polygon 
                  points={ghostPoints} 
                  fill="none" 
                  stroke="#fbbf24" 
                  strokeWidth="2" 
                  strokeDasharray="2 2"
                  className="animate-pulse"
               />
            )}

            {/* Actual Data Shape */}
            <polygon points={points} fill="rgba(205, 32, 39, 0.1)" stroke="#cd2027" strokeWidth="1.5" />

            {/* Labels */}
            <text x="80" y="15" textAnchor="middle" fontSize="6" fill="#9ca3af" className="uppercase font-mono">Brand</text>
            <text x="135" y="100" textAnchor="middle" fontSize="6" fill="#9ca3af" className="uppercase font-mono">Sales</text>
            <text x="25" y="100" textAnchor="middle" fontSize="6" fill="#9ca3af" className="uppercase font-mono">Reach</text>
        </svg>
    </div>
  );
};

