import React from 'react';
import { ServiceStats } from '../types';

interface StatsRadarProps {
  stats: ServiceStats;
  potentialStats?: ServiceStats; // New: For "Ghost" projection
}

const StatsRadar: React.FC<StatsRadarProps> = ({ stats, potentialStats }) => {
  // Use a simpler coordinate system 0-100
  const MAX_VAL = 40; 
  const norm = (val: number) => Math.min((val / MAX_VAL) * 100, 100);

  // Center (50, 50) Radius ~35 to leave room for labels
  const cx = 50;
  const cy = 55;
  const r = 35;

  const getPoints = (s: ServiceStats) => {
    const v1 = norm(s.brand); // Top
    const v2 = norm(s.conversion); // Right
    const v3 = norm(s.reach); // Left

    // Top point
    const x1 = cx;
    const y1 = cy - (r * (v1 / 100));

    // Right point (30 deg from horizontal, or 330 deg total? Triangle is 120 apart)
    // Top is 270 deg. Right is 30 deg (down right). Left is 150 deg (down left)

    // Convert degrees to radians: deg * PI / 180
    // Top (-90 deg or 270) -> sin is -1, cos is 0

    // Bottom Right (30 deg)
    const ang2 = 30 * (Math.PI / 180); 
    const x2 = cx + (r * (v2 / 100)) * Math.cos(ang2);
    const y2 = cy + (r * (v2 / 100)) * Math.sin(ang2);

    // Bottom Left (150 deg)
    const ang3 = 150 * (Math.PI / 180);
    const x3 = cx + (r * (v3 / 100)) * Math.cos(ang3);
    const y3 = cy + (r * (v3 / 100)) * Math.sin(ang3);

    return `${x1},${y1} ${x2},${y2} ${x3},${y3}`;
  };

  const points = getPoints(stats);
  const ghostPoints = potentialStats ? getPoints(potentialStats) : '';

  // Background Triangle Points (Max value)
  const bgPoints = `50,${cy-r} ${cx + r * Math.cos(30 * Math.PI / 180)},${cy + r * Math.sin(30 * Math.PI / 180)} ${cx + r * Math.cos(150 * Math.PI / 180)},${cy + r * Math.sin(150 * Math.PI / 180)}`;

  return (
    <div className="w-full h-full">
        <svg width="100%" height="100%" viewBox="0 0 100 100" preserveAspectRatio="xMidYMid meet" className="overflow-visible">
            {/* Background Grid */}
            <polygon points={bgPoints} fill="#f9fafb" stroke="#e5e7eb" strokeWidth="0.5" />

            {/* Inner Grid (50%) - approximate */}
            <polygon points={`50,${cy-r/2} ${cx + r/2 * Math.cos(30*Math.PI/180)},${cy + r/2 * Math.sin(30*Math.PI/180)} ${cx + r/2 * Math.cos(150*Math.PI/180)},${cy + r/2 * Math.sin(150*Math.PI/180)}`} fill="none" stroke="#e5e7eb" strokeWidth="0.5" strokeDasharray="2 2" />

            {/* Axis Lines */}
            <line x1={cx} y1={cy} x2={cx} y2={cy-r} stroke="#f3f4f6" strokeWidth="0.5" />
            <line x1={cx} y1={cy} x2={cx + r * Math.cos(30*Math.PI/180)} y2={cy + r * Math.sin(30*Math.PI/180)} stroke="#f3f4f6" strokeWidth="0.5" />
            <line x1={cx} y1={cy} x2={cx + r * Math.cos(150*Math.PI/180)} y2={cy + r * Math.sin(150*Math.PI/180)} stroke="#f3f4f6" strokeWidth="0.5" />

            {/* Ghost Shape */}
            {potentialStats && (
               <polygon 
                  points={ghostPoints} 
                  fill="none" 
                  stroke="#fbbf24" 
                  strokeWidth="1" 
                  strokeDasharray="2 1"
                  className="animate-pulse"
               />
            )}

            {/* Actual Data Shape */}
            <polygon points={points} fill="rgba(205, 32, 39, 0.15)" stroke="#cd2027" strokeWidth="1.5" strokeLinejoin="round" />

            {/* Labels - Larger and better positioned */}
            <text x="50" y="12" textAnchor="middle" fontSize="6" fontWeight="bold" fill="#000" className="uppercase font-mono tracking-wider">Brand</text>
            <text x="92" y="85" textAnchor="middle" fontSize="6" fontWeight="bold" fill="#000" className="uppercase font-mono tracking-wider">Sales</text>
            <text x="8" y="85" textAnchor="middle" fontSize="6" fontWeight="bold" fill="#000" className="uppercase font-mono tracking-wider">Reach</text>
        </svg>
    </div>
  );
};

