          className="w-full py-4 bg-black text-white text-xs uppercase tracking-[0.2em] font-bold hover:bg-[#cd2027] transition-all flex items-center justify-center gap-3 border border-black shadow-[4px_4px_0px_0px_rgba(0,0,0,0.2)] hover:shadow-none hover:translate-x-[2px] hover:translate-y-[2px]"
