            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
          />
          <button 
            type="submit"
            className="absolute right-1 top-1 bottom-1 px-4 bg-gray-100 hover:bg-black hover:text-white text-[9px] font-bold transition-colors uppercase tracking-wider border-l border-gray-200"
          >
            {emailSent ? 'ENVIADO' : 'ENVIAR'}
          </button>
        </form>
      </div>
    </div>
  );
};

