                <div className="flex items-center justify-between">
                     <div className="flex items-center gap-2">
                        <span className={`w-2 h-2 ${recommendation.type === 'oversale' ? 'bg-blue-600' : 'bg-amber-600'} rounded-full animate-pulse`}></span>
                        <p className={`text-[10px] font-bold uppercase tracking-widest ${recommendation.type === 'oversale' ? 'text-blue-900' : 'text-amber-900'}`}>
                            {recommendation.type === 'oversale' ? 'Redundancia' : 'Oportunidad'}
                        </p>
                     </div>
                     <button 
                        onClick={() => onRecommendationAction(recommendation.serviceId, 'dismiss')}
                        className={`
                            px-2 py-1 text-[9px] font-bold uppercase tracking-wider border rounded transition-colors
                            ${recommendation.type === 'oversale' 
                                ? 'border-blue-200 text-blue-400 hover:border-blue-400 hover:text-blue-800' 
                                : 'border-amber-200 text-amber-400 hover:border-amber-400 hover:text-amber-800'}
                        `}
                     >
                        Omitir
                     </button>
                </div>

                <p className={`text-xs font-mono leading-snug pl-3 border-l-2 ${recommendation.type === 'oversale' ? 'text-blue-800 border-blue-300' : 'text-amber-800 border-amber-300'}`}>
                    {recommendation.text}
                </p>

                {recommendation.serviceName && (
                    <button 
                        onClick={() => onRecommendationAction(recommendation.serviceId, recommendation.type === 'oversale' ? 'remove' : 'add')}
                        className={`
                            w-full py-3 text-[10px] font-bold uppercase tracking-widest transition-all shadow-sm flex justify-center items-center gap-2
                            ${recommendation.type === 'oversale' 
                                ? 'bg-white border border-blue-900 text-blue-900 hover:bg-blue-900 hover:text-white' 
                                : 'bg-white border border-amber-900 text-amber-900 hover:bg-amber-900 hover:text-white'
                            }
                        `}
                    >
                        {recommendation.type === 'oversale' ? (
                            <>
                                <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="5" y1="12" x2="19" y2="12"/></svg>
                                Eliminar {recommendation.serviceName}
                            </>
                        ) : (
                            <>
                                <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>
                                Añadir {recommendation.serviceName}
                            </>
                        )}
                    </button>
                )}
            </div>
        </div>
      )}

      {/* Action Footer */}
      <div className="p-6 bg-white border-t-2 border-black space-y-4 mt-auto">
        <button 
          onClick={onGeneratePdf}
          className="w-full py-4 bg-black text-white text-xs uppercase tracking-[0.2em] font-bold hover:bg-[#cd2027] transition-all flex items-center justify-center gap-3 border border-black shadow-[4px_4px_0px_0px_rgba(0,0,0,0.2)] hover:shadow-none hover:translate-x-[2px] hover:translate-y-[2px]"
        >
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
          </svg>
          Exportar Informe PDF
        </button>

        <form onSubmit={handleSendEmail} className="relative group">
          <input 
            type="email" 
            placeholder="EMAIL_DESTINO..." 
            className="w-full text-xs font-mono p-3 pl-4 bg-white border border-gray-300 focus:border-black focus:ring-0 outline-none transition-colors uppercase placeholder:text-gray-300"
            value={email}
