import React from 'react';
import { Service, Tier } from '../types';

interface ServiceCardProps {
  service: Service;
  selectedTierId: string | undefined; // If undefined, not selected
  isRelated: boolean; // Prop to trigger lightbulb
  onToggle: (id: string, tierId?: 'essential' | 'pro' | 'premium') => void;
}

const ServiceCard: React.FC<ServiceCardProps> = ({ service, selectedTierId, isRelated, onToggle }) => {
  const isSelected = !!selectedTierId;
  const minPrice = Math.min(...service.tiers.map(t => t.price));

  const handleCardClick = () => {
    if (!isSelected) {
      onToggle(service.id, 'pro');
    } else {
        onToggle(service.id);
    }
  };

  const handleTierClick = (e: React.MouseEvent, tierId: 'essential' | 'pro' | 'premium') => {
    e.stopPropagation(); 
    onToggle(service.id, tierId);
  };

  const getDurationLabel = (duration: number, unit: 'days' | 'weeks' | 'hours') => {
      if (unit === 'weeks') return duration > 1 ? 'semanas' : 'semana';
      if (unit === 'days') return duration > 1 ? 'días' : 'día';
      if (unit === 'hours') return duration > 1 ? 'horas' : 'hora';
      return '';
  }

  // New List Parser Function
  const renderDescriptionList = (text: string) => {
    const lines = text.split('\n');
    return (
      <ul className="space-y-1 my-3">
        {lines.map((line, idx) => {
          const isSubItem = line.trim().startsWith('-');
          const content = isSubItem ? line.replace('-', '').trim() : line.trim();

          return (
            <li 
              key={idx} 
              className={`text-xs ${isSubItem ? 'pl-3 text-gray-500 italic' : 'text-gray-700 font-medium'} flex items-start`}
            >
               {!isSubItem && <span className="mr-1.5 text-[#cd2027] text-[10px] mt-[3px]">■</span>}
               {isSubItem && <span className="mr-1.5 text-gray-300 text-[10px]">-</span>}
               <span>{content}</span>
            </li>
          );
        })}
      </ul>
    );
  };

  return (
    <div 
      className={`
        relative border p-6 transition-all duration-300 flex flex-col group min-h-[220px] bg-white
        ${isSelected 
          ? 'border-[#cd2027] shadow-[4px_4px_0px_0px_rgba(205,32,39,0.1)] z-10' 
          : 'border-gray-200 hover:border-black hover:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.1)]'
        }
      `}
    >
      {/* Lightbulb Recommendation */}
      {isRelated && !isSelected && (
        <div className="absolute -top-3 -right-3 w-8 h-8 bg-yellow-400 flex items-center justify-center shadow-md animate-bounce z-20 border border-black" title="Recomendado por sinergia">
           <svg className="w-5 h-5 text-black" fill="none" viewBox="0 0 24 24" stroke="currentColor">
             <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
           </svg>
        </div>
      )}

      {/* Header Section */}
      <div className="cursor-pointer flex-grow" onClick={handleCardClick}>
          <div className="flex justify-between items-start mb-3">
            <h3 className={`font-semibold text-base transition-colors pr-2 leading-tight uppercase tracking-tight ${isSelected ? 'text-black' : 'text-gray-900'}`}>
              {service.name}
            </h3>
            <div className={`
              w-4 h-4 border transition-colors flex items-center justify-center flex-shrink-0
              ${isSelected ? 'bg-[#cd2027] border-[#cd2027]' : 'border-gray-300 bg-white group-hover:border-black'}
            `}>
              {isSelected && (
                <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                </svg>
              )}
            </div>
          </div>

          <p className="text-sm text-gray-500 mb-6 font-light leading-relaxed font-mono text-xs">
            {service.description}
          </p>

          {/* Stats Preview (Mini) - NOW WITH REACH */}
          {!isSelected && (
            <div className="flex gap-3 mb-4 mt-auto">
                <div className="flex flex-col items-center flex-1">
                    <span className="h-1 w-full bg-gray-100 overflow-hidden relative">
                        <span className="block h-full bg-black absolute left-0 top-0" style={{width: `${(service.stats.brand/10)*100}%`}}></span>
                    </span>
                    <span className="text-[8px] text-gray-400 mt-1 uppercase font-mono tracking-tighter">Brand</span>
                </div>
                 <div className="flex flex-col items-center flex-1">
                    <span className="h-1 w-full bg-gray-100 overflow-hidden relative">
                        <span className="block h-full bg-black absolute left-0 top-0" style={{width: `${(service.stats.conversion/10)*100}%`}}></span>
                    </span>
                    <span className="text-[8px] text-gray-400 mt-1 uppercase font-mono tracking-tighter">Sale</span>
                </div>
                <div className="flex flex-col items-center flex-1">
                    <span className="h-1 w-full bg-gray-100 overflow-hidden relative">
                        <span className="block h-full bg-black absolute left-0 top-0" style={{width: `${(service.stats.reach/10)*100}%`}}></span>
                    </span>
                    <span className="text-[8px] text-gray-400 mt-1 uppercase font-mono tracking-tighter">Reach</span>
                </div>
            </div>
          )}
      </div>

      {/* Tier Selector */}
      {isSelected ? (
          <div className="mt-4 pt-4 border-t border-dashed border-gray-300 animate-fadeIn">
            <div className="flex justify-between items-center mb-3">
                <p className="text-[10px] uppercase text-gray-400 font-bold tracking-wider font-mono">Nivel Táctico</p>
                <button onClick={(e) => {e.stopPropagation(); onToggle(service.id)}} className="text-[10px] text-red-600 hover:bg-red-50 px-1 font-mono uppercase"> [ Eliminar ] </button>
            </div>

            <div className="grid grid-cols-3 gap-[-1px] mb-4 border border-black">
                {service.tiers.map((tier) => (
                    <button
                        key={tier.id}
                        onClick={(e) => handleTierClick(e, tier.id)}
                        className={`
                            py-2 text-[9px] sm:text-[10px] transition-all text-center font-bold uppercase tracking-wide border-r border-black last:border-r-0 px-1
                            ${selectedTierId === tier.id 
                                ? 'bg-black text-white' 
                                : 'bg-white text-gray-500 hover:bg-gray-50 hover:text-black'
                            }
                        `}
                    >
                        {tier.name}
                    </button>
                ))}
            </div>
            {/* Active Tier Details */}
            {service.tiers.map(tier => (
                 selectedTierId === tier.id && (
                    <div key={tier.id} className="text-xs bg-gray-50 p-4 border border-gray-200">
                        <div className="mb-2">
                             {renderDescriptionList(tier.description)}
                        </div>
                        <div className="flex justify-between items-center pt-3 border-t border-gray-200 mt-3">
                            <span className="text-[#cd2027] font-bold text-sm font-mono">{tier.price} €</span>
                            <span className="text-black font-medium font-mono text-[10px] uppercase">{tier.duration} {getDurationLabel(tier.duration, tier.unit)}</span>
                        </div>
                         {/* Mini Resource Counter */}
                         {(tier.resources.photos > 0 || tier.resources.videos > 0 || tier.resources.posts > 0) && (
                            <div className="flex gap-3 mt-2 pt-2 border-t border-dashed border-gray-300 text-[10px] text-gray-500 font-mono">
                                {tier.resources.photos > 0 && <span>FOTOS:{tier.resources.photos}</span>}
                                {tier.resources.videos > 0 && <span>VIDEOS:{tier.resources.videos}</span>}
                                {tier.resources.posts > 0 && <span>POSTS:{tier.resources.posts}</span>}
                            </div>
                         )}
                    </div>
                 )
            ))}
          </div>
      ) : (
        /* Default Footer */
        <div className="flex items-center justify-between pt-4 border-t border-gray-100 mt-auto">
            <span className="text-sm font-bold text-gray-900 font-mono">
            {minPrice} € <span className="text-[10px] font-normal text-gray-400">/ min</span>
            </span>
            <span className="text-[9px] text-black uppercase tracking-widest border border-gray-200 px-2 py-1 hover:bg-black hover:text-white transition-colors">
                Select
            </span>
        </div>
      )}

      <style>{`
        @keyframes fadeIn {
            from { opacity: 0; transform: translateY(-5px); }
            to { opacity: 1; transform: translateY(0); }
        }
        .animate-fadeIn {
            animation: fadeIn 0.2s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

