import { Category, Tier, Resources } from './types';

// Helper to generate tiers with specific resource counts
const createTiers = (
  basePrice: number, 
  baseDays: number, 
  unit: 'days'|'weeks'|'hours', 
  details: [string, string, string],
  resourceBase: Partial<Resources> = {}
): Tier[] => {
  const defaults: Resources = { photos: 0, videos: 0, posts: 0, hours: 0 };
  const r = { ...defaults, ...resourceBase };

  return [
    { 
      id: 'essential', name: 'Essential', price: basePrice, duration: baseDays, unit, description: details[0],
      resources: { ...r, hours: unit === 'hours' ? baseDays : 0 }
    },
    { 
      id: 'pro', name: 'Pro', price: Math.round(basePrice * 1.8), duration: Math.ceil(baseDays * 1.5), unit, description: details[1],
      resources: { 
        photos: Math.round(r.photos * 1.5), 
        videos: Math.round(r.videos * 1.5), 
        posts: Math.round(r.posts * 1.5),
        hours: unit === 'hours' ? Math.ceil(baseDays * 1.5) : 0
      }
    },
    { 
      id: 'premium', name: 'Premium', price: basePrice * 3, duration: baseDays * 2, unit, description: details[2],
      resources: { 
        photos: r.photos * 3, 
        videos: r.videos * 3, 
        posts: r.posts * 3,
        hours: unit === 'hours' ? baseDays * 2 : 0
      }
    }
  ];
};

// --- NEW HELPER: Subscription / Packs Logic ---
const createSubscriptionTiers = (
  monthlyPrice: number,
  details: [string, string, string],
  resourceBase: Partial<Resources>
): Tier[] => {
  const defaults: Resources = { photos: 0, videos: 0, posts: 0, hours: 0 };
  const r = { ...defaults, ...resourceBase };

  // Logic: 
  // 1 Month: Base
  // 3 Months: -5% total
  // 6 Months: -10% total

  return [
    { 
      id: 'essential', 
      name: '1 Mes', 
      price: monthlyPrice, 
      duration: 4, unit: 'weeks', 
      description: details[0],
      resources: r 
    },
    { 
      id: 'pro', 
      name: '3 Meses (-5%)', 
      price: Math.round(monthlyPrice * 3 * 0.95), 
      duration: 12, unit: 'weeks', 
      description: details[1] + '\n(-5% Dto. aplicado)',
      resources: { 
        photos: (r.photos || 0) * 3,
        videos: (r.videos || 0) * 3,
        posts: (r.posts || 0) * 3,
        hours: (r.hours || 0) * 3
      }
    },
    { 
      id: 'premium', 
      name: '6 Meses (-10%)', 
      price: Math.round(monthlyPrice * 6 * 0.90), 
      duration: 24, unit: 'weeks', 
      description: details[2] + '\n(-10% Dto. aplicado)',
      resources: { 
         photos: (r.photos || 0) * 6,
         videos: (r.videos || 0) * 6,
         posts: (r.posts || 0) * 6,
         hours: (r.hours || 0) * 6
      }
    }
  ];
};

