import React from 'react';
import { ProjectObjective } from '../types';

interface ObjectiveSelectorProps {
  objectives: ProjectObjective[];
  selectedObjectiveId: string | null;
  onSelect: (id: string) => void;
}

const ObjectiveSelector: React.FC<ObjectiveSelectorProps> = ({ objectives, selectedObjectiveId, onSelect }) => {
  return (
    <div className="mb-12">
      <h3 className="text-[10px] uppercase font-bold tracking-[0.2em] text-gray-400 mb-4">¿Cuál es el objetivo principal de tu proyecto?</h3>
      <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
        {objectives.map((obj) => {
          const isActive = selectedObjectiveId === obj.id;
          return (
            <button
              key={obj.id}
              onClick={() => onSelect(obj.id)}
              className={`
                flex flex-col items-center justify-center p-4 border transition-all duration-300 group
                ${isActive 
                  ? 'border-black bg-black text-white shadow-[4px_4px_0px_0px_rgba(0,0,0,0.1)]' 
                  : 'border-gray-200 bg-white hover:border-black text-gray-500 hover:text-black'
                }
              `}
            >
              <span className="text-2xl mb-2 group-hover:scale-110 transition-transform">{obj.icon}</span>
              <span className="text-[10px] font-bold uppercase tracking-wider text-center leading-tight">
                {obj.title}
              </span>
              <span className={`text-[8px] mt-1 font-mono hidden md:block ${isActive ? 'text-gray-400' : 'text-gray-300'}`}>
                {obj.subtitle}
              </span>
            </button>
          );
        })}
      </div>
    </div>
  );
};

export default ObjectiveSelector;

