import React from 'react';
import { ProjectObjective } from '../types';

interface ObjectiveSelectorProps {
  objectives: ProjectObjective[];
  selectedObjectiveId: string | null;
  onSelect: (id: string) => void;
}

const IconReach = () => (
  <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
    <path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"/>
  </svg>
);

const IconSales = () => (
  <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
    <path d="M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z"/><path d="M3 6h18"/><path d="M16 10a4 4 0 0 1-8 0"/>
  </svg>
);

const IconIdentity = () => (
  <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
    <path d="M12 3l9 4.2v9.6L12 21l-9-4.2V7.2L12 3z"/><path d="M12 12l9-4.2M12 12v9M12 12L3 7.8"/>
  </svg>
);

const IconProduct = () => (
  <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
    <path d="M21 8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16Z"/><path d="M3.27 6.96L12 12.01l8.73-5.05"/><path d="M12 22.08V12"/>
  </svg>
);

const IconDigital = () => (
  <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
    <circle cx="12" cy="12" r="10"/><path d="M2 12h20M12 2a15.3 15.3 0 0 1 0 20"/>
  </svg>
);

const ObjectiveSelector: React.FC<ObjectiveSelectorProps> = ({ objectives, selectedObjectiveId, onSelect }) => {
  const getIcon = (type: string) => {
    switch(type) {
      case 'reach': return <IconReach />;
      case 'sales': return <IconSales />;
      case 'identity': return <IconIdentity />;
      case 'product': return <IconProduct />;
      case 'digital': return <IconDigital />;
      default: return null;
    }
  };

  return (
    <div className="mb-12">
      <div className="flex items-center gap-2 mb-4">
          <div className="w-1 h-1 bg-black rounded-full"></div>
          <h3 className="text-[10px] uppercase font-bold tracking-[0.2em] text-gray-400">Objetivo de Proyecto</h3>
      </div>
      <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
        {objectives.map((obj) => {
          const isActive = selectedObjectiveId === obj.id;
          return (
            <button
              key={obj.id}
              onClick={() => onSelect(obj.id)}
              className={`
                flex flex-col items-center justify-center p-5 border transition-all duration-500 group relative overflow-hidden
                ${isActive 
                  ? 'border-black bg-black text-white shadow-[8px_8px_0px_0px_rgba(0,0,0,0.1)]' 
                  : 'border-gray-200 bg-white hover:border-black text-gray-500 hover:text-black'
                }
              `}
            >
              {/* Decorative scanline for active objective */}
              {isActive && <div className="absolute top-0 left-0 w-full h-[1px] bg-white/20 animate-scan"></div>}

              <div className={`mb-3 transition-transform duration-500 ${isActive ? 'scale-110' : 'group-hover:scale-105'}`}>
                  {getIcon(obj.icon)}
              </div>
              <span className="text-[10px] font-bold uppercase tracking-wider text-center leading-tight mb-1">
                {obj.title}
              </span>
              <span className={`text-[8px] font-mono tracking-tighter opacity-60 ${isActive ? 'text-gray-300' : 'text-gray-400'}`}>
                {obj.subtitle}
              </span>
            </button>
          );
        })}
      </div>
      <style>{`
        @keyframes scan {
          0% { top: 0; }
          100% { top: 100%; }
        }
        .animate-scan {
          animation: scan 2s linear infinite;
        }
      `}</style>
    </div>
  );
};

export default ObjectiveSelector;

import React, { useState } from 'react';
import { Category } from '../types';
import ServiceCard from './ServiceCard';

interface CategorySectionProps {
  category: Category;
  selectedServices: Map<string, string>; // ID -> TierID
  relatedServices: Set<string>; // IDs of related services to highlight
  onToggleService: (id: string, tierId?: 'essential' | 'pro' | 'premium') => void;
  isActive: boolean;
}

const CategorySection: React.FC<CategorySectionProps> = ({ 
  category, 
  selectedServices, 
  relatedServices,
  onToggleService,
  isActive
}) => {
  const [activeSubTab, setActiveSubTab] = useState<string>(category.subcategories[0]?.id || '');

  const activeSubcategory = category.subcategories.find(sub => sub.id === activeSubTab);

  return (
    <div className={`mb-16 transition-opacity duration-500 ${isActive ? 'opacity-100' : 'opacity-80 hover:opacity-100'}`}>
      <div className="flex items-baseline gap-3 mb-6 border-b border-black pb-2">
        <h2 className={`text-2xl font-light uppercase tracking-tight ${isActive ? 'text-black' : 'text-gray-400'}`}>
          {category.title}
        </h2>
        {isActive && <span className="text-[9px] uppercase tracking-widest bg-black text-white px-2 py-0.5 font-bold">ONLINE</span>}
      </div>

      {/* Horizontal Tabs Navigation */}
      <div className="flex overflow-x-auto gap-[-1px] mb-8 no-scrollbar">
        {category.subcategories.map(sub => {
            const isTabActive = activeSubTab === sub.id;

            // Calculate how many services are selected in this subcategory
            const selectedCount = sub.services.filter(s => selectedServices.has(s.id)).length;

            // CHECK FOR HIDDEN RECOMMENDATIONS:
            // Does this subcategory have a service that is RECOMMENDED but NOT SELECTED?
            const hasHiddenRecommendation = sub.services.some(s => 
              relatedServices.has(s.id) && !selectedServices.has(s.id)
            );

            return (
                <button
                    key={sub.id}
                    onClick={() => setActiveSubTab(sub.id)}
                    className={`
                        whitespace-nowrap px-6 py-4 text-[10px] font-bold uppercase tracking-wider transition-all relative border border-gray-300 border-r-0 last:border-r flex items-center gap-2
                        ${isTabActive 
                            ? 'bg-black text-white border-black z-10' 
                            : 'text-gray-500 bg-white hover:bg-gray-50 hover:text-black'
                        }
                    `}
                >
                    {sub.title}

                    {/* Discovery Alert (Sparkle Icon) */}
                    {hasHiddenRecommendation && !isTabActive && (
                        <span className="flex items-center animate-pulse" title="Sugerencia táctica disponible">
                            <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="#fbbf24" strokeWidth="2.5">
                                <path d="M12 3l1.912 5.885L20 10.8l-5.088 1.915L13.912 18.6 12 12.715l-1.912 5.885L8.088 12.715 3 10.8l5.088-1.915L10.088 3z" fill="#fbbf24" />
                            </svg>
                        </span>
                    )}

                    {selectedCount > 0 && (
                        <span className={`
                            flex items-center justify-center w-5 h-5 text-[9px] font-mono border
                            ${isTabActive 
                                ? 'bg-[#cd2027] text-white border-[#cd2027]' 
                                : 'bg-gray-200 text-black border-gray-300'
                            }
                        `}>
                            {selectedCount}
                        </span>
                    )}
                </button>
            )
        })}
      </div>

      {/* Content Area */}
      <div className="min-h-[200px]">
        {activeSubcategory && (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-fadeIn">
                {activeSubcategory.services.map(service => (
                <ServiceCard
                    key={service.id}
                    service={service}
                    selectedTierId={selectedServices.get(service.id)}
                    isRelated={relatedServices.has(service.id)}
                    onToggle={onToggleService}
                />
                ))}
            </div>
        )}
      </div>

      <style>{`
        @keyframes fadeIn {
            from { opacity: 0; transform: translateY(5px); }
            to { opacity: 1; transform: translateY(0); }
        }
        .animate-fadeIn {
            animation: fadeIn 0.3s ease-out forwards;
        }
        .no-scrollbar::-webkit-scrollbar {
            display: none;
        }
        .no-scrollbar {
            -ms-overflow-style: none;
            scrollbar-width: none;
        }
      `}</style>
    </div>
  );
};

