const IconReach = () => <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"/></svg>;
const IconSales = () => <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><path d="M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z"/><path d="M3 6h18"/><path d="M16 10a4 4 0 0 1-8 0"/></svg>;
const IconIdentity = () => <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><path d="M12 3l9 4.2v9.6L12 21l-9-4.2V7.2L12 3z"/><path d="M12 12l9-4.2M12 12v9M12 12L3 7.8"/></svg>;
const IconProduct = () => <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><path d="M21 8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16Z"/><path d="M3.27 6.96L12 12.01l8.73-5.05"/><path d="M12 22.08V12"/></svg>;
const IconDigital = () => <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><circle cx="12" cy="12" r="10"/><path d="M2 12h20M12 2a15.3 15.3 0 0 1 0 20"/></svg>;

const StatsRadar = ({ stats, potentialStats }: { stats: ServiceStats, potentialStats?: ServiceStats }) => {
  const cx = 60, cy = 60, r = 40;
  const norm = (v: number) => Math.min((v / 40) * 100, 100);
  const getP = (s: ServiceStats) => {
    const v1 = norm(s.brand), v2 = norm(s.conversion), v3 = norm(s.reach);
    const x1 = cx, y1 = cy - (r * (v1/100));
    const x2 = cx + (r * (v2/100)) * Math.cos(30*Math.PI/180), y2 = cy + (r * (v2/100)) * Math.sin(30*Math.PI/180);
    const x3 = cx + (r * (v3/100)) * Math.cos(150*Math.PI/180), y3 = cy + (r * (v3/100)) * Math.sin(150*Math.PI/180);
    return `${x1},${y1} ${x2},${y2} ${x3},${y3}`;
  };
  return (
    <svg width="100%" height="100%" viewBox="0 0 120 120" className="overflow-visible">
      <polygon points={`60,${cy-r} ${cx+r*0.86},${cy+r*0.5} ${cx-r*0.86},${cy+r*0.5}`} fill="none" stroke="#eee" strokeWidth="1" />
      {potentialStats && <polygon points={getP(potentialStats)} fill="none" stroke="#fbbf24" strokeWidth="1" strokeDasharray="2" className="animate-pulse" />}
      <polygon points={getP(stats)} fill="rgba(205,32,39,0.1)" stroke="#cd2027" strokeWidth="1.5" />
      <text x="60" y="10" textAnchor="middle" fontSize="6" className="uppercase font-mono">Brand</text>
      <text x="110" y="90" textAnchor="middle" fontSize="6" className="uppercase font-mono">Sale</text>
      <text x="10" y="90" textAnchor="middle" fontSize="6" className="uppercase font-mono">Reach</text>
    </svg>
  );
};

const ServiceCard = ({ service, selectedTierId, isRelated, onToggle }: { service: Service, selectedTierId?: string, isRelated: boolean, onToggle: any }) => {
  const isSelected = !!selectedTierId;
  return (
    <div onClick={() => isSelected ? onToggle(service.id) : onToggle(service.id, 'pro')} className={`p-5 border transition-all cursor-pointer bg-white relative ${isSelected ? 'border-[#cd2027] shadow-lg scale-[1.02]' : 'border-gray-100 hover:border-black'}`}>
      {isRelated && !isSelected && <div className="absolute -top-2 -right-2 bg-amber-400 p-1 border border-black animate-bounce"><IconReach /></div>}
      <h4 className="font-bold text-xs uppercase mb-1">{service.name}</h4>
      <p className="text-[10px] text-gray-400 mb-4 font-mono">{service.description}</p>
      <div className="flex gap-2 mb-4">
        {['brand','conversion','reach'].map(k => <div key={k} className="flex-1 h-0.5 bg-gray-100 relative"><div className="absolute inset-0 bg-black" style={{width:`${((service.stats as any)[k]/10)*100}%`}}></div></div>)}
      </div>
      {isSelected ? (
        <div className="grid grid-cols-3 gap-1 mt-4">
          {service.tiers.map(t => <button key={t.id} onClick={(e) => {e.stopPropagation(); onToggle(service.id, t.id)}} className={`text-[8px] p-2 border border-black uppercase font-bold ${selectedTierId === t.id ? 'bg-black text-white' : 'bg-white text-black'}`}>{t.name}</button>)}
        </div>
      ) : <div className="text-[9px] font-bold uppercase tracking-widest text-right mt-2">+ Seleccionar</div>}
    </div>
  );
};

// --- 4. MAIN APP ---
const App = () => {
  const [selectedMap, setSelectedMap] = useState<Map<string, TierID>>(new Map());
  const [objectiveId, setObjectiveId] = useState<string | null>(null);
  const [isPortfolio, setIsPortfolio] = useState(false);

  const toggle = (sid: string, tid?: TierID) => {
    const next = new Map(selectedMap);
    if (!tid) next.delete(sid); else next.set(sid, tid);
    setSelectedMap(next);
  };

  const selectedList = useMemo(() => {
    const list: SelectedServiceUI[] = [];
    selectedMap.forEach((tid, sid) => {
      DATA.forEach(c => c.subcategories.forEach(sub => {
        const s = sub.services.find(ser => ser.id === sid);
        if (s) {
          const t = s.tiers.find(tr => tr.id === tid)!;
          list.push({ serviceId: sid, name: s.name, tierId: tid, price: t.price, duration: t.duration, stats: s.stats, resources: t.resources });
        }
      }));
    });
    return list;
  }, [selectedMap]);

  const totals = useMemo(() => {
    let p = 0, d = 0, br = 0, co = 0, re = 0, ph = 0, vi = 0, po = 0;
    selectedList.forEach(i => {
      const m = i.tierId === 'pro' ? 1.2 : (i.tierId === 'premium' ? 1.5 : 1);
      p += i.price; d += i.duration; br += i.stats.brand*m; co += i.stats.conversion*m; re += i.stats.reach*m;
      ph += i.resources.photos; vi += i.resources.videos; po += i.resources.posts;
    });
    const synD = selectedList.length >= 3 ? 0.15 : (selectedList.length === 2 ? 0.10 : 0);
    const sAmt = Math.round(p * synD);
    const portAmt = isPortfolio ? Math.round((p - sAmt) * 0.20) : 0;
    return { originalPrice: p, synergyDiscountAmount: sAmt, portfolioDiscountAmount: portAmt, finalPrice: p - sAmt - portAmt, maxDays: d, totalStats: { brand: br, conversion: co, reach: re }, totalResources: { photos: ph, videos: vi, posts: po, hours: 0 }, isPortfolioActive: isPortfolio } as Totals;
  }, [selectedList, isPortfolio]);

  const relatedSet = useMemo(() => {
    const set = new Set<string>();
    if (objectiveId) OBJECTIVES.find(o => o.id === objectiveId)?.recommendedServiceIds.forEach(id => set.add(id));
    return set;
  }, [objectiveId]);

  return (
    <div className="max-w-6xl mx-auto p-4 md:p-10 grid grid-cols-1 lg:grid-cols-12 gap-10">
      <div className="lg:col-span-8">
        <header className="mb-10 border-l-4 border-[#cd2027] pl-6">
          <h1 className="text-3xl font-bold uppercase tracking-tighter">Planificador La Grieta</h1>
          <p className="text-gray-400 text-sm font-mono mt-1 uppercase tracking-widest">Sinergia táctica v2.0</p>
        </header>

        <section className="mb-12">
          <h3 className="text-[10px] uppercase font-bold tracking-widest text-gray-400 mb-4">¿Cuál es tu objetivo?</h3>
          <div className="grid grid-cols-2 md:grid-cols-5 gap-2">
            {OBJECTIVES.map(o => (
              <button key={o.id} onClick={() => setObjectiveId(o.id === objectiveId ? null : o.id)} className={`p-4 border transition-all flex flex-col items-center ${o.id === objectiveId ? 'bg-black text-white border-black' : 'bg-white border-gray-100 hover:border-black text-gray-400 hover:text-black'}`}>
                {o.id === 'reach' && <IconReach />} {o.id === 'sales' && <IconSales />} {o.id === 'identity' && <IconIdentity />} {o.id === 'product' && <IconProduct />} {o.id === 'digital' && <IconDigital />}
                <span className="text-[9px] font-bold uppercase mt-2">{o.title}</span>
              </button>
            ))}
          </div>
        </section>

        {DATA.map(cat => (
          <div key={cat.id} className="mb-12">
            <h2 className="text-xl font-bold uppercase mb-6 border-b border-gray-100 pb-2">{cat.title}</h2>
            {cat.subcategories.map(sub => (
              <div key={sub.id} className="mb-8">
                <h3 className="text-[10px] font-bold text-[#cd2027] uppercase tracking-widest mb-4">{sub.title}</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {sub.services.map(s => <ServiceCard key={s.id} service={s} selectedTierId={selectedMap.get(s.id)} isRelated={relatedSet.has(s.id)} onToggle={toggle} />)}
                </div>
              </div>
            ))}
          </div>
        ))}
      </div>

      <div className="lg:col-span-4">
        <div className="sticky top-10 border-2 border-black p-6 bg-white shadow-xl">
          <h3 className="text-[10px] font-bold uppercase tracking-[0.3em] mb-4 text-gray-400">Resumen de Inversión</h3>
          <div className="text-4xl font-bold font-mono mb-6">{totals.finalPrice}€</div>

          <div className="space-y-3 mb-8">
            <div className="flex justify-between text-xs font-mono text-gray-400"><span>Subtotal</span><span>{totals.originalPrice}€</span></div>
            {totals.synergyDiscountAmount > 0 && <div className="flex justify-between text-xs font-mono text-[#cd2027]"><span>Sinergia</span><span>-{totals.synergyDiscountAmount}€</span></div>}
            <div onClick={() => setIsPortfolio(!isPortfolio)} className={`p-3 border cursor-pointer transition-colors ${isPortfolio ? 'bg-black text-white border-black' : 'bg-gray-50 border-gray-100'}`}>
              <div className="flex justify-between items-center"><span className="text-[9px] font-bold uppercase">Protocolo Portfolio</span><span className="text-[9px] font-bold">-20%</span></div>
            </div>
          </div>

          <div className="h-40 mb-6"><StatsRadar stats={totals.totalStats} /></div>

          <div className="grid grid-cols-3 gap-2 mb-8 text-center">
            {[['FOTOS', totals.totalResources.photos],['VIDEOS', totals.totalResources.videos],['POSTS', totals.totalResources.posts]].map(r => (
              <div key={r[0]} className="p-2 border border-gray-100"><div className="text-xs font-bold">{r[1]}</div><div className="text-[7px] text-gray-400">{r[0]}</div></div>
            ))}
          </div>

          <button className="w-full py-4 bg-black text-white text-[10px] font-bold uppercase tracking-widest hover:bg-[#cd2027] transition-all">Generar PDF Oficial</button>
        </div>
      </div>
    </div>
  );
};

