// --- 4. COMPONENTS ---
const StatsRadar = ({ stats, potentialStats }: { stats: ServiceStats, potentialStats?: ServiceStats }) => {
  const cx = 60, cy = 60, r = 40;
  const norm = (v: number) => Math.min((v / 40) * 100, 100);
  const getP = (s: ServiceStats) => {
    const v1 = norm(s.brand), v2 = norm(s.conversion), v3 = norm(s.reach);
    const x1 = cx, y1 = cy - (r * (v1/100));
    const x2 = cx + (r * (v2/100)) * Math.cos(30*Math.PI/180), y2 = cy + (r * (v2/100)) * Math.sin(30*Math.PI/180);
    const x3 = cx + (r * (v3/100)) * Math.cos(150*Math.PI/180), y3 = cy + (r * (v3/100)) * Math.sin(150*Math.PI/180);
    return `${x1},${y1} ${x2},${y2} ${x3},${y3}`;
  };
  return (
    <svg width="100%" height="100%" viewBox="0 0 120 120" className="overflow-visible">
      <polygon points={`60,${cy-r} ${cx+r*0.86},${cy+r*0.5} ${cx-r*0.86},${cy+r*0.5}`} fill="none" stroke="#eee" strokeWidth="1" />
      {potentialStats && <polygon points={getP(potentialStats)} fill="none" stroke="#fbbf24" strokeWidth="1" strokeDasharray="2" className="animate-pulse" />}
      <polygon points={getP(stats)} fill="rgba(205,32,39,0.05)" stroke="#cd2027" strokeWidth="1.2" />
      <text x="60" y="8" textAnchor="middle" fontSize="6" className="uppercase font-mono font-bold" fill="#aaa">Brand</text>
      <text x="115" y="100" textAnchor="middle" fontSize="6" className="uppercase font-mono font-bold" fill="#aaa">Sale</text>
      <text x="5" y="100" textAnchor="middle" fontSize="6" className="uppercase font-mono font-bold" fill="#aaa">Reach</text>
    </svg>
  );
};

const ServiceCard = ({ service, selectedTierId, isRelated, onToggle }: { service: Service, selectedTierId?: string, isRelated: boolean, onToggle: any }) => {
  const isSelected = !!selectedTierId;
  return (
    <div onClick={() => isSelected ? onToggle(service.id) : onToggle(service.id, 'pro')} className={`p-6 border transition-all cursor-pointer bg-white relative group ${isSelected ? 'border-[#cd2027] shadow-[8px_8px_0px_0px_rgba(205,32,39,0.05)]' : 'border-gray-100 hover:border-black'}`}>
      {isRelated && !isSelected && <div className="absolute -top-2 -right-2 bg-amber-400 p-1 border border-black animate-bounce z-10"><IconReach /></div>}
      <h4 className="font-bold text-xs uppercase mb-1 tracking-tight">{service.name}</h4>
      <p className="text-[10px] text-gray-400 mb-4 font-mono leading-relaxed">{service.description}</p>
      <div className="flex gap-2 mb-4">
        {['brand','conversion','reach'].map(k => <div key={k} className="flex-1 h-0.5 bg-gray-100 relative"><div className="absolute inset-0 bg-black" style={{width:`${((service.stats as any)[k]/10)*100}%`}}></div></div>)}
      </div>
      {isSelected ? (
        <div className="grid grid-cols-3 gap-1 mt-4 border border-black">
          {service.tiers.map(t => <button key={t.id} onClick={(e) => {e.stopPropagation(); onToggle(service.id, t.id)}} className={`text-[8px] p-2 uppercase font-bold transition-colors ${selectedTierId === t.id ? 'bg-black text-white' : 'bg-white text-black hover:bg-gray-50'}`}>{t.name}</button>)}
        </div>
      ) : <div className="text-[9px] font-bold uppercase tracking-widest text-right mt-2 opacity-0 group-hover:opacity-100 transition-opacity">+ Seleccionar</div>}
    </div>
  );
};

// --- 5. MAIN APP ---
const App = () => {
  const [selectedMap, setSelectedMap] = useState<Map<string, TierID>>(new Map());
  const [objectiveId, setObjectiveId] = useState<string | null>(null);
  const [isPortfolio, setIsPortfolio] = useState(false);
  const [activeTab, setActiveTab] = useState<string>(DATA[0].id);
  const [activeSubTab, setActiveSubTab] = useState<Map<string, string>>(new Map(DATA.map(c => [c.id, c.subcategories[0].id])));

  const toggle = (sid: string, tid?: TierID) => {
    const next = new Map(selectedMap);
    if (!tid) next.delete(sid); else next.set(sid, tid);
    setSelectedMap(next);
  };

  const selectedList = useMemo(() => {
    const list: SelectedServiceUI[] = [];
    selectedMap.forEach((tid, sid) => {
      DATA.forEach(c => c.subcategories.forEach(sub => {
        const s = sub.services.find(ser => ser.id === sid);
        if (s) {
          const t = s.tiers.find(tr => tr.id === tid)!;
          list.push({ serviceId: sid, name: s.name, tierId: tid, price: t.price, duration: t.duration, stats: s.stats, resources: t.resources });
        }
      }));
    });
    return list;
  }, [selectedMap]);

  const totals = useMemo(() => {
    let p = 0, d = 0, br = 0, co = 0, re = 0, ph = 0, vi = 0, po = 0;
    selectedList.forEach(i => {
      const m = i.tierId === 'pro' ? 1.2 : (i.tierId === 'premium' ? 1.5 : 1);
      p += i.price; d += i.duration; br += i.stats.brand*m; co += i.stats.conversion*m; re += i.stats.reach*m;
      ph += i.resources.photos; vi += i.resources.videos; po += i.resources.posts;
    });
    const synD = selectedList.length >= 3 ? 0.15 : (selectedList.length === 2 ? 0.10 : 0);
    const sAmt = Math.round(p * synD);
    const portAmt = isPortfolio ? Math.round((p - sAmt) * 0.20) : 0;
    return { originalPrice: p, synergyDiscountAmount: sAmt, portfolioDiscountAmount: portAmt, finalPrice: p - sAmt - portAmt, maxDays: d, totalStats: { brand: br, conversion: co, reach: re }, totalResources: { photos: ph, videos: vi, posts: po, hours: 0 }, isPortfolioActive: isPortfolio } as Totals;
  }, [selectedList, isPortfolio]);

  const relatedSet = useMemo(() => {
    const set = new Set<string>();
    if (objectiveId) OBJECTIVES.find(o => o.id === objectiveId)?.recommendedServiceIds.forEach(id => set.add(id));
    return set;
  }, [objectiveId]);

  return (
    <div className="max-w-7xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-10 bg-white">
      {/* Columna Izquierda: Selectores y Servicios */}
      <div className="lg:col-span-8">
        <header className="mb-12 border-l-8 border-[#cd2027] pl-8">
          <h1 className="text-4xl font-black uppercase tracking-tighter leading-none">LA GRIETA <span className="font-light">PLANNER</span></h1>
          <p className="text-gray-400 text-[10px] font-mono mt-2 uppercase tracking-[0.4em]">Sinergia Táctica · Protocolo v2.5</p>
        </header>

        {/* Selector de Objetivos */}
        <section className="mb-16">
          <div className="flex items-center gap-2 mb-4">
             <div className="w-1.5 h-1.5 bg-black rounded-full"></div>
             <h3 className="text-[10px] uppercase font-bold tracking-[0.2em] text-gray-500">Objetivo del Proyecto</h3>
          </div>
          <div className="grid grid-cols-2 md:grid-cols-5 gap-2">
            {OBJECTIVES.map(o => (
              <button key={o.id} onClick={() => setObjectiveId(o.id === objectiveId ? null : o.id)} className={`flex flex-col items-center justify-center p-5 border transition-all relative overflow-hidden group ${o.id === objectiveId ? 'bg-black text-white border-black' : 'bg-white border-gray-100 text-gray-400 hover:border-black hover:text-black'}`}>
                {o.id === objectiveId && <div className="absolute top-0 left-0 w-full h-[1px] bg-white/20 animate-scan"></div>}
                <div className="mb-2 group-hover:scale-110 transition-transform">
                  {o.id === 'reach' && <IconReach />} {o.id === 'sales' && <IconSales />} {o.id === 'identity' && <IconIdentity />} {o.id === 'product' && <IconProduct />} {o.id === 'digital' && <IconDigital />}
                </div>
                <span className="text-[9px] font-bold uppercase tracking-wider text-center">{o.title}</span>
              </button>
            ))}
          </div>
        </section>

        {/* Navegación de Categorías Principales */}
        <nav className="flex gap-8 mb-8 border-b border-gray-100 pb-2 overflow-x-auto no-scrollbar">
           {DATA.map(cat => (
             <button key={cat.id} onClick={() => setActiveTab(cat.id)} className={`text-xs uppercase font-bold tracking-widest pb-2 transition-all relative ${activeTab === cat.id ? 'text-black' : 'text-gray-300 hover:text-black'}`}>
                {cat.title}
                {activeTab === cat.id && <div className="absolute bottom-[-1px] left-0 w-full h-0.5 bg-[#cd2027]"></div>}
             </button>
           ))}
        </nav>

        {/* Contenido de la Categoría Activa */}
        {DATA.filter(c => c.id === activeTab).map(cat => (
          <div key={cat.id} className="animate-fade">
             {/* Subpestañas con Sparkles de Recomendación */}
             <div className="flex gap-1 mb-8 overflow-x-auto no-scrollbar">
                {cat.subcategories.map(sub => {
                  const isSubActive = activeSubTab.get(cat.id) === sub.id;
                  const hasHiddenRec = sub.services.some(s => relatedSet.has(s.id) && !selectedMap.has(s.id));
                  return (
                    <button key={sub.id} onClick={() => setActiveSubTab(new Map(activeSubTab).set(cat.id, sub.id))} className={`px-4 py-3 text-[9px] font-bold uppercase tracking-widest border transition-all flex items-center gap-2 ${isSubActive ? 'bg-black text-white border-black' : 'bg-white border-gray-100 text-gray-500 hover:bg-gray-50'}`}>
                      {sub.title}
                      {hasHiddenRec && !isSubActive && <span className="animate-pulse text-amber-400">✦</span>}
                    </button>
                  );
                })}
             </div>

             {/* Rejilla de Servicios */}
             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {cat.subcategories.find(s => s.id === activeSubTab.get(cat.id))?.services.map(s => (
                  <ServiceCard key={s.id} service={s} selectedTierId={selectedMap.get(s.id)} isRelated={relatedSet.has(s.id)} onToggle={toggle} />
                ))}
             </div>
          </div>
        ))}
      </div>

      {/* Columna Derecha: Resumen Técnico */}
      <div className="lg:col-span-4">
        <div className="sticky top-10 border-2 border-black p-8 bg-white shadow-[12px_12px_0px_0px_rgba(0,0,0,0.05)]">
           <div className="flex justify-between items-baseline mb-2">
              <h3 className="text-[10px] font-bold uppercase tracking-[0.3em] text-gray-400">Presupuesto Estimado</h3>
              <span className="text-[8px] font-mono text-gray-300 uppercase">Ref_2024_01</span>
           </div>
           <div className="text-5xl font-black font-mono tracking-tighter mb-8">{totals.finalPrice}€</div>

           <div className="space-y-4 mb-10 pb-10 border-b border-gray-100">
              <div className="flex justify-between text-[11px] font-mono">
                 <span className="text-gray-400">VALOR BASE</span>
                 <span className="font-bold">{totals.originalPrice}€</span>
              </div>
              {totals.synergyDiscountAmount > 0 && (
                <div className="flex justify-between text-[11px] font-mono text-[#cd2027]">
                   <span className="font-bold uppercase tracking-wider">SINERGIA ({selectedList.length >= 3 ? '15%' : '10%'})</span>
                   <span className="font-bold">-{totals.synergyDiscountAmount}€</span>
                </div>
              )}
              <div onClick={() => setIsPortfolio(!isPortfolio)} className={`p-4 border cursor-pointer transition-all ${isPortfolio ? 'bg-black text-white border-black' : 'bg-gray-50 border-gray-100 text-gray-400 hover:border-black hover:text-black'}`}>
                 <div className="flex justify-between items-center">
                    <span className="text-[9px] font-bold uppercase tracking-widest">Protocolo P0RT4F0L10</span>
                    <span className="text-[9px] font-bold">-20%</span>
                 </div>
              </div>
           </div>

           <div className="mb-10">
              <p className="text-[10px] font-bold uppercase tracking-[0.2em] text-gray-400 mb-6">Análisis de Impacto</p>
              <div className="h-44 relative mb-4">
                 <StatsRadar stats={totals.totalStats} />
              </div>
              <div className="grid grid-cols-3 gap-1 text-center">
                 <div className="p-3 border border-gray-50"><div className="text-xs font-bold font-mono">{totals.totalResources.photos}</div><div className="text-[7px] text-gray-400 font-bold">FOTOS</div></div>
