// --- 1. TYPES & INTERFACES ---
type TierID = 'essential' | 'pro' | 'premium';

interface ServiceStats { brand: number; conversion: number; reach: number; }
interface Resources { photos: number; videos: number; posts: number; hours: number; }
interface Tier { 
  id: TierID; name: string; price: number; duration: number; 
  unit: 'days' | 'weeks' | 'hours'; description: string; resources: Resources; 
}
interface Service { 
  id: string; name: string; description: string; tiers: Tier[]; 
  stats: ServiceStats; relatedServiceIds: string[]; 
}
interface Subcategory { id: string; title: string; services: Service[]; }
interface Category { id: string; title: string; description: string; subcategories: Subcategory[]; }
interface ProjectObjective { id: string; title: string; subtitle: string; icon: string; recommendedServiceIds: string[]; }
interface SelectedServiceUI { 
  serviceId: string; name: string; tierId: TierID; price: number; 
  duration: number; stats: ServiceStats; resources: Resources; 
}
interface Totals {
  originalPrice: number; synergyDiscountAmount: number; portfolioDiscountAmount: number;
  finalPrice: number; minDays: number; maxDays: number; synergyLevel: number;
  isPortfolioActive: boolean; totalStats: ServiceStats; totalResources: Resources;
}

