const createTiers = (p: number, d: number, u: 'days'|'weeks'|'hours', desc: [string, string, string], rb: Partial<Resources> = {}): Tier[] => {
  const r = { photos: 0, videos: 0, posts: 0, hours: 0, ...rb };
  return [
    { id: 'essential', name: 'Essential', price: p, duration: d, unit: u, description: desc[0], resources: { ...r, hours: u === 'hours' ? d : 0 } },
    { id: 'pro', name: 'Pro', price: Math.round(p * 1.8), duration: Math.ceil(d * 1.5), unit: u, description: desc[1], resources: { photos: Math.round(r.photos * 1.5), videos: Math.round(r.videos * 1.5), posts: Math.round(r.posts * 1.5), hours: u === 'hours' ? Math.ceil(d * 1.5) : 0 } },
    { id: 'premium', name: 'Premium', price: p * 3, duration: d * 2, unit: u, description: desc[2], resources: { photos: r.photos * 3, videos: r.videos * 3, posts: r.posts * 3, hours: u === 'hours' ? d * 2 : 0 } }
  ];
};

