    { id: 'premium', name: 'Premium', price: p * MULTIPLIERS.PREMIUM, duration: d * 2, unit: u, description: desc[2], resources: { photos: r.photos * 3, videos: r.videos * 3, posts: r.posts * 3, hours: u === 'hours' ? d * 2 : 0 } }
  ];
};

